-- patch skill descriptions and names, as they do not have valid handles in EE.

function PatchSkillText()
	local LightningBolt = Ext.GetStat("Projectile_LightningBolt")
    LightningBolt.Description = "<font size='19'>Поразите целевого персонажа разрядом молнии, который пробивает цель насквозь <font color='858580' size='18' face='Averia Serif'>(аналогично «Клыку снайпера»)</font> и наносит [1].</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>+25% урона (+4% за Аэротеургию) в момент применения.<br><font color='46b195'>2 (требование: 5 Аэротеургия): </font>+20% урона (+3% за Аэротеургию) в момент применения. Получите способность «Электрический разряд x1» на 2 хода, стоимостью 3 ОД, перезарядка 1 ход, наносит на 50% больше урона и накладывает 'удушение'.<br><font color='46b195'>3 (требование: 9 Аэротеургия): </font>+20% урона(+4% за Аэротеургию) в момент применения. Способность «Электрический разряд x1» теперь дается на 3 хода. Повторное применение на всех видимых противниках в радиусе 13м.<br> </font>"
	
	local DazingBolt = Ext.GetStat("ProjectileStrike_DazingBolt")
    DazingBolt.Description = "<font size='19'>С небес обрушивается электрический разряд, наносящий [1] персонажам в [2] области.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>+25% урона (+4% за Аэротеургию) в момент применения. Накладывает 1 <font color='188EDE'>Harried</font> (+0.2 за Аэротеургию).<br><font color='46b195'>2 (требование: 5 Аэротеургия): </font>+40% урона (+8% за Аэротеургию) в момент применения. Накладывает 2 <font color='188EDE'>Harried</font> (+0.3 за Аэротеургию). <br><font color='46b195'>3 (требование: 9 Аэротеургия): </font>Применяется снова на каждого задетого в области применения противника.<br> </font>"
	
	local ClosedCircuit = Ext.GetStat("Shout_ElectricFence")
    ClosedCircuit.Description = "<font size='19'>Создайте кольцо электризованной воды вокруг себя и нанесите [1] противникам в радиусе [2].<br><br><font color='7F25D4'>Terrified III</font> требует 7 <font color='188EDE'>Harried</font>:<br>Отключение атак по возможности, нельзя обнаружить персонажей в скрытности и трата ОД от устрашения.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>+25% урона (+4% за Аэротеургию) в момент применения.<br><font color='46b195'>2 (требование: 5 Аэротеургия): </font>Получите +30% урона (+6% за Аэротеургию) в момент применения за каждого противника с эффектом 'заряд' в области действия способности.<br><font color='46b195'>3 (требование: 9 Аэротеургия): </font>(Этот эффект очень часто багуется!!!)<br>Урон от способности срабатывает дважды и активирует детонацию 'заряда' на всех противниках в области действия.<br><font color='858580' size='18' face='Averia Serif'><br>Описания уровневых эффектов есть в дневнике.</font></font>"
	
	local IncarnateClosedCircuit = Ext.GetStat("Shout_IncarnateElectricFence")
    IncarnateClosedCircuit.Description = "<font size='19'>Создайте кольцо электризованной воды вокруг себя и нанесите [1] противникам в радиусе [2].<br><br><font color='7F25D4'>Terrified III</font> требует 7 <font color='188EDE'>Harried</font>:<br>Отключение атак по возможности, нельзя обнаружить персонажей в скрытности и трата ОД от устрашения.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>+25% урона (+4% за Аэротеургию) в момент применения.<br><font color='46b195'>2 (требование: 5 Аэротеургия): </font>Получите +30% урона (+6% за Аэротеургию) в момент применения за каждого противника с эффектом 'заряд' в области действия способности.<br><font color='46b195'>3 (требование: 9 Аэротеургия): </font>(Этот эффект очень часто багуется!!!)<br>Урон от способности срабатывает дважды и активирует детонацию 'заряда' на всех противниках в области действия.<br><font color='858580' size='18' face='Averia Serif'><br>Описания уровневых эффектов есть в дневнике.</font></font>"
	
	local Thunderstorm = Ext.GetStat("Target_AMER_Storm_Lightning")
    Thunderstorm.Description = "<font size='19'>Призовите грозовое облако в [2] область на 2 хода, которое выпускает пять электрических разрядов. Каждый разряд наносит [1] в [3] радиусе при применении способности и в конце каждого вашего хода, задевая одного противника один раз (оставшееся количество разрядов наносят урон случайным образом).<br><br><font color='858580' size='18' face='Averia Serif'>Область можно переместить один раз в ход.</font></font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>+1 ход длительности.<br><font color='46b195'>2 (требование: 5 Аэротеургия): </font>Разряды молний накладывают эффект <font color='797980'>Dazzled</font> (вплоть до II уровня) на 2 хода. +3 разряда молний.<br><font color='46b195'>3 (требование: 9 Аэротеургия): </font>Перед применением, телепортируйте всех задетых противников (не Боссов) в центр области применения. +3 разряда молний. Восстановите 1 очко Истока.<br><font color='858580' size='18' face='Averia Serif'><br>Описания уровневых эффектов есть в дневнике.</font></font>"

    local Blizzard = Ext.GetStat("Target_AMER_Storm_Blizzard")
    Blizzard.Description = "<font size='19'>Призовите морозное облако в [2] область на 2 хода, с которого падают пять ледяных осколков. Каждый осколок наносит [1] в [3] радиусе при применении способности и в конце каждого вашего хода, задевая одного противника только один раз (оставшееся количество осколков наносят урон случайным образом).<br><br><font color='858580' size='18' face='Averia Serif'>Область можно переместить один раз в ход.</font></font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>+1 ход длительности.<br><font color='46b195'>2 (требование: 5 Гидрософистика): </font>Осколки накладывают 1 стак <font color='188EDE'>Harried</font>.<br><font color='46b195'>3 (требование: 9 Гидрософистика): </font>+3 осколка. Осколки накладывают эффект <font color='B97A57'>Slowed</font> (вплоть до III уровня). Восстановите 1 очко Истока.<br> </font>"

    local EtherealStorm = Ext.GetStat("Target_AMER_Storm_Ethereal")
    EtherealStorm.Description = "<font size='19'>Призовите стихийное облако в [2] область на 2 хода, с которого беспорядочно падают пять стихийных снарядов. Каждый снаряд наносят [1] ед. урона огнем, водой, землей или ядом в [4] радиусе (союзникам восстанавливает [3]), задевая одну цель только один раз (оставшееся количество снарядов падают случайным образом).<br><br><font color='858580' size='18' face='Averia Serif'>Область можно переместить один раз в ход.</font></font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>+1 ход длительности.<br><font color='46b195'>2 (требование: 5 Призывание): </font>+3 снаряда. Снаряды накладывают эффект <font color='7F25D4'>Terrified</font> (вплоть до II уровня) на 2 хода.<br><font color='46b195'>3 (требование: 9 Призывание): </font>Вне лимита призванных существ, призывает инкарната со всеми не стихийными насыщениями в точке применения. Восстановите 1 очко Истока.<br><font color='858580' size='18' face='Averia Serif'><br>Описания уровневых эффектов есть в дневнике.</font></font>"

    local Scourge = Ext.GetStat("Target_AMER_Storm_Scourge")
    Scourge.Description = "<font size='19'>Призовите кровавое облако в [2] область на 2 хода, с которого падают восемь кровавых сгустков. Каждый сгусток наносит [1] в [3] радиусе при применении способности и в конце каждого вашего хода, задевая одного противника только один раз (оставшееся количество сгустков наносят урон случайным образом).<br><br><font color='858580' size='18' face='Averia Serif'>Область можно переместить один раз в ход.</font></font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>Призывает труп в 2м от целевой точки, который наносит противникам [4] в [3] области.<br><font color='46b195'>2 (требование: 5 Некромантия): </font>Призывает по 1 трупу каждый ход (падающие трупы наносят двойной урон).<br><font color='46b195'>3 (требование: 9 Некромантия): </font>После применения, союзники в радиусе 13м, у которых есть как минимум 1 очко Некромантии, бесплатной реакцией ритуала используют «Взрыв трупа» на разных не взорванных трупах в бою, в области применения. За каждых двух участников ритуала призывается дополнительный труп.<br> </font>"

    local ShockingTouch = Ext.GetStat("Target_ShockingTouch")
    ShockingTouch.Description = "<font size='19'>Нанесите [1]. <font color='c80030'>Заплатите до 4 ОД:</font> За каждое недостающее ОД вы получаете 2 стака <font color='c80030'>Battered</font> и <font color='188EDE'>Harried</font>.<br><br><font color='ff9e9e'>Subjugated III</font> требует 7 <font color='c80030'>Battered</font>:<br>Уменьшенная вероятность нападения на владельца эффекта (при атаке получает урон водой), штраф к восстановлению ОД.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>У вас всегда остается как минимум 1 ОД после применения. +25% урона (+4% за Аэротеургию) в момент применения.<br><font color='46b195'>2 (требование: 5 Аэротеургия): </font>Перед применением наложите эффект 'Дезинтеграция: Воздух 25%' (+2.5% за Аэротеургию) на 1 ход: при окончании этого эффекта, цель получает процентный урон от общего полученного урона за время его действия (урон воздухом).<br><font color='46b195'>3 (требование: 9 Аэротеургия): </font>'Дезинтеграция' длится 2 хода. +1% к урону 'Дезинтеграции' за Аэротеургию. Накладывает 2 <font color='188EDE'>Harried</font> (+0.2 за Аэротеургию).<br><font color='858580' size='18' face='Averia Serif'><br>Описания уровневых эффектов есть в дневнике.</font></font>"

    local BoneWidow = Ext.GetStat("Summon_BonePile")
    BoneWidow.Description = "<font size='19'>Призовите костяную вдову, которая наносит физический урон и обладает способностями «Закопаться» и «Сожрать труп».</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>Вдова получает 2 хода генерации Истока и способность «Взгляд онемения».<br><font color='46b195'>2 (требование: 5 Некромантия): </font>Вдова получает 2 очка Истока, способность «Призыв внутреннего демона» и призывается сразу с эффектом одного съеденного трупа. При смерти, создает 1 труп (за каждый съеденный), в случайной точке в радиусе 2м.<br><font color='46b195'>3 (требование: 9 Некромантия): </font>Вдова получает способности «Гуща битвы» и «Призыв костяного скитальца» и также ваши значения умений Некромантии и Призывания. Восстановите 1 очко Истока.<br> </font>"

    local Fireball = Ext.GetStat("Projectile_Fireball")
    Fireball.Description = "<font size='19'>Запустите огненный шар в целевую область, который наносит [1] и создает поверхность огня в [2] радиусе.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>+25% урона (+4% за Пирокинетику) в момент применения.<br><font color='46b195'>2 (требование: 5 Пирокинетика): </font>+40% урона (+8% за Пирокинетику) в момент применения. Восстановите 2 ОД.<br><font color='46b195'>3 (требование: 9 Пирокинетика): </font>Применяется снова на всех видимых противников в радиусе 13м.<br> </font>"

    local IncarnateFireball = Ext.GetStat("Projectile_IncarnateFireball")
    IncarnateFireball.Description = "<font size='19'>Запустите огненный шар в целевую область, который наносит [1] и создает поверхность огня в [2] радиусе.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>+25% урона (+4% за Пирокинетику) в момент применения.<br><font color='46b195'>2 (требование: 5 Пирокинетика): </font>+40% урона (+8% за Пирокинетику) в момент применения. Восстановите 2 ОД.<br><font color='46b195'>3 (требование: 9 Пирокинетика): </font>Применяется снова на всех видимых противников в радиусе 13м.<br> </font>"

    local FossilStrike = Ext.GetStat("Projectile_PyroclasticRock")
    FossilStrike.Description = "<font size='19'>Запустите огромный булыжник, который наносит [1] и создает поверхность нефти в [2] радиусе.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>+25% урона (+4% за Геомантию) в момент применения. <br><font color='46b195'>2 (требование: 5 Геомантия): </font>+40% урона (+8% за Геомантию) в момент применения. <br><font color='46b195'>3 (требование: 9 Геомантия): </font>Союзники в радиусе 15м, у которых есть как минимум 1 очко Геомантии, бесплатной реакцией ритуала используют «Каменный удар» на всех видимых противников в радиусе 13м от них. Повторно используется на всех противников в радиусе 13м.<br> </font>"

    local Impalement = Ext.GetStat("Target_RockSpikes")
    Impalement.Description = "<font size='19'>Каменные колья вызываются из-под земли, наносят [1] и создают поверхность нефти в [2] радиусе.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>+25% урона (+4% за Геомантию) в момент применения.<br><font color='46b195'>2 (требование: 5 Геомантия): </font>Повторите базовый эффект. Накладывает 'кровотечение' на 2 хода.<br><font color='46b195'>3 (требование: 9 Геомантия): </font>Повторите базовый эффект 3 раза. <br> </font>"

    local ThrowDust = Ext.GetStat("Projectile_ThrowDust")
    ThrowDust.Description = "<font size='19'>Бросьте горсть пыли в целевую область, которая наносит [1] противникам и очищает поверхности в [2] области.<br><br><font color='797980'>Dazzled III</font> требует 7 <font color='188EDE'>Harried</font>:<br>Слепота (видимость 3м), нельзя обнаружить персонажей в скрытности, снижение точности и уклонения.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>+25% урона (+4% за Геомантию) в момент применения. <br><font color='46b195'>2 (требование: 5 Геомантия): </font>Повторите базовый эффект. Накладывает 2 <font color='188EDE'>Harried</font> (+0.35 за Геомантию).<br><font color='46b195'>3 (требование: 9 Геомантия): </font>Получите способность «Бросок пыли x1» на 3 хода, стоимость 2 ОД, перезарядка 1 ход, накладывает Wither на 1 ход, накладывает 1 <font color='188EDE'>Harried</font>. Повторите базовый эффект 4 раза. <br><font color='858580' size='18' face='Averia Serif'><br>Описания уровневых эффектов есть в дневнике.</font></font>"

    local EmpoweredThrowDust = Ext.GetStat("Projectile_ThrowDust_Empowered")
    EmpoweredThrowDust.Description = "<font size='19'>Бросьте горсть пыли в целевую область, наносит [1] противникам и очищает поверхности в [2] радиусе.<br><br><font color='797980'>Dazzled III</font> требует 7 <font color='188EDE'>Harried</font>:<br>Слепота (видимость 3м), нельзя обнаружить персонажей в скрытности, снижение точности и уклонения.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>+25% урона (+4% за Геомантию) в момент применения. <br><font color='46b195'>2 (требование: 5 Геомантия): </font>Повторите базовый эффект. Накладывает 2 <font color='188EDE'>Harried</font> (+0.35 за Геомантию).<br><font color='46b195'>3 (требование: 9 Геомантия): </font>Получите способность «Бросок пыли x1» на 3 хода, стоимость 2 ОД, перезарядка 1 ход, накладывает Wither на 1 ход, накладывает 1 <font color='188EDE'>Harried</font>. Повторите базовый эффект 4 раза. <br><font color='858580' size='18' face='Averia Serif'><br>Описания уровневых эффектов есть в дневнике.</font></font>"

    local Miasma = Ext.GetStat("Shout_PoisonWave")
    Miasma.Description = "<font size='19'>Призовите зловонные испарения из недр земли, которые наносят [1] противникам и союзникам нежити, создавая ядовитые облака в [2] радиусе вокруг вас. Получите эффект <font color='ffffff'>Ядовитая волна</font>, который дает <font color='11D77A'>иммунитет к окаменению, отравлению</font> (если не нежить) и +[3]% сопротивления земле и +[4]% сопротивления яду.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>Повторите базовый эффект 1 раз на начало вашего следующего хода.<br><font color='46b195'>2 (требование: 5 Геомантия): </font>Повторите базовый эффект 1 раз на начало вашего следующего хода. Повторное наложение также накладывает 'окаменение' на 2 хода. Накладывает Wither на 1 ход и 'окаменение' на 2 хода противникам в радиусе 5м.<br><font color='46b195'>3 (требование: 9 Геомантия): </font>Повторите базовый эффект 2 раза на начало вашего следующего хода. Повторите базовый эффект 7 раз в момент применения.<br> </font>"

    local PlantMiasma = Ext.GetStat("Shout_PlantAcidWave")
    PlantMiasma.Description = "<font size='19'>Призовите зловонные испарения из недр земли, которые наносят [1] противникам и союзникам нежити, создавая ядовитые облака в [2] радиусе вокруг вас. Получите эффект <font color='ffffff'>Ядовитая волна</font>, который дает <font color='11D77A'>иммунитет к окаменению, отравлению</font> (если не нежить) и +[3]% сопротивления земле и +[4]% сопротивления яду.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>Повторите базовый эффект 1 раз на начало вашего следующего хода.<br><font color='46b195'>2 (требование: 5 Геомантия): </font>Повторите базовый эффект 1 раз на начало вашего следующего хода. Повторное наложение также накладывает 'окаменение' на 2 хода. Накладывает Wither на 1 ход и 'окаменение' на 2 хода противникам в радиусе 5м.<br><font color='46b195'>3 (требование: 9 Геомантия): </font>Повторите базовый эффект 2 раза на начало вашего следующего хода. Повторите базовый эффект 7 раз в момент применения.<br> </font>"

    local AcidSpores = Ext.GetStat("Projectile_AcidSpores")
    AcidSpores.Description = "<font size='19'>Выпустите [3] ядовитых споры, которые наносят [1] и создают ядовитые облака в [2] радиусе.<br><font color='c80030'>Заплатите до 5 ОД:</font> За каждое недостающее ОД вы получаете 2 стака <font color='c80030'>Battered</font> и <font color='188EDE'>Harried</font>.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>У вас всегда остается как минимум 1 ОД после применения. +10% урона (+2% за Геомантию) в момент применения. <br><font color='46b195'>2 (требование: 5 Геомантия): </font>Стаки <font color='c80030'>Battered</font> и <font color='188EDE'>Harried</font> за недостающие ОД больше не накладываются. Дополнительный выстрел 1 спорой по каждой цели. Восстановите 1 очко Истока. <br><font color='46b195'>3 (требование: 9 Геомантия): </font>Накладывает Withered и 'разъедание' на 1 ход, и кислоту, кровотечение, кровоизлияние и удушение на 3 хода.<br> </font>"

    local PlantAcidSpores = Ext.GetStat("Projectile_PlantAcidSpore")
    PlantAcidSpores.Description = "<font size='19'>Выпустите [3] ядовитых споры, которые наносят [1] и создают ядовитые облака в [2] радиусе.<br><font color='c80030'>Заплатите до 5 ОД:</font> За каждое недостающее ОД вы получаете 2 стака <font color='c80030'>Battered</font> и <font color='188EDE'>Harried</font>.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>У вас всегда остается как минимум 1 ОД после применения. +10% урона (+2% за Геомантию) в момент применения. <br><font color='46b195'>2 (требование: 5 Геомантия): </font>Стаки <font color='c80030'>Battered</font> и <font color='188EDE'>Harried</font> за недостающие ОД больше не накладываются. Дополнительный выстрел 1 спорой по каждой цели. Восстановите 1 очко Истока. <br><font color='46b195'>3 (требование: 9 Геомантия): </font>Накладывает Withered и 'разъедание' на 1 ход, и кислоту, кровотечение, кровоизлияние и удушение на 3 хода.<br> </font>"

    local IncarnateAcidSpores = Ext.GetStat("Projectile_IncarnateAcidSpores")
    IncarnateAcidSpores.Description = "<font size='19'>Выпустите [3] ядовитых споры, которые наносят [1] и создают ядовитые облака в [2] радиусе.<br><font color='c80030'>Заплатите до 5 ОД:</font> За каждое недостающее ОД вы получаете 2 стака <font color='c80030'>Battered</font> и <font color='188EDE'>Harried</font>.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>У вас всегда остается как минимум 1 ОД после применения. +10% урона (+2% за Геомантию) в момент применения. <br><font color='46b195'>2 (требование: 5 Геомантия): </font>Стаки <font color='c80030'>Battered</font> и <font color='188EDE'>Harried</font> за недостающие ОД больше не накладываются. Дополнительный выстрел 1 спорой по каждой цели. Восстановите 1 очко Истока. <br><font color='46b195'>3 (требование: 9 Геомантия): </font>Накладывает Withered и 'разъедание' на 1 ход, и кислоту, кровотечение, кровоизлияние и удушение на 3 хода.<br> </font>"

    local CorrosiveTouch = Ext.GetStat("Target_CorrosiveTouch")
    CorrosiveTouch.Description = "<font size='19'>Уничтожьте [1] целевому персонажу.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>Накладывает 'Дезинтеграция: Колющий 25%' (+2.5% за Геомантию) в момент применения: при окончании эффекта противник получает процентный урон от общего полученного урона за время действия эффекта (колющий урон). Накладывает 'разъедание' на 1 ход.<br><font color='46b195'>2 (требование: 5 Геомантия): </font>Накладывает 2 <font color='c80030'>Battered</font> (+0.2 за Геомантию). Накладывает Withered на 2 хода. 'Дезинтеграция' длится 1 ход.<br><font color='46b195'>3 (требование: 9 Геомантия): </font>'Дезинтеграция' длится 2 хода. +1% к урону Дезинтеграции за Геомантию. +30% урона (+5% за Геомантию) в момент применения.<br> </font>"

    local CorrosiveSpray = Ext.GetStat("Cone_CorrosiveSpray")
    CorrosiveSpray.Description = "<font size='19'>Уничтожьте [1] противникам в [3]-градусном [2] конусе.<br><br><font color='b823cb'>Vulnerable III</font> требует 7 <font color='c80030'>Battered</font>:<br>Порча (урон от лечения). Проще наложить стаки Battered/Harried.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>+10% урона (+3% за Геомантию) в момент применения. Накладывает 'разъедание' на 1 ход.<br><font color='46b195'>2 (требование: 5 Геомантия): </font>Накладывает ‘Дезинтеграция: Физический 25%’ (+2.5% за Геомантию) на 1 ход: при окончании этого эффекта, противник получает процентный урон от общего полученного урона за время его действия (урон землей). Повторите базовый эффект (физическим уроном).<br><font color='46b195'>3 (требование: 9 Геомантия): </font>Накладывает 'удушение' на 2 хода. 'Дезинтеграция' длится 2 хода. +1% к урону 'Дезинтеграции' за Геомантию. Повторите базовый эффект (физическим уроном).<br><font color='858580' size='18' face='Averia Serif'><br>Описания уровневых эффектов есть в дневнике.</font></font>"

    local IncarnateCorrosiveSpray = Ext.GetStat("Cone_IncarnateCorrosiveSpray")
    IncarnateCorrosiveSpray.Description = "<font size='19'>Уничтожьте [1] противникам в [3]-градусном [2] конусе.<br><br><font color='b823cb'>Vulnerable III</font> требует 7 <font color='c80030'>Battered</font>:<br>Порча (урон от лечения). Проще наложить стаки Battered/Harried.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>+10% урона (+3% за Геомантию) в момент применения. Накладывает 'разъедание' на 1 ход.<br><font color='46b195'>2 (требование: 5 Геомантия): </font>Накладывает ‘Дезинтеграция: Физический 25%’ (+2.5% за Геомантию) на 1 ход: при окончании этого эффекта, противник получает процентный урон от общего полученного урона за время его действия (урон землей). Повторите базовый эффект (физическим уроном).<br><font color='46b195'>3 (требование: 9 Геомантия): </font>Накладывает 'удушение' на 2 хода. 'Дезинтеграция' длится 2 хода. +1% к урону 'Дезинтеграции' за Геомантию. Повторите базовый эффект (физическим уроном).<br><font color='858580' size='18' face='Averia Serif'><br>Описания уровневых эффектов есть в дневнике.</font></font>"

    local ReactiveArmor = Ext.GetStat("Shout_ReactiveArmor")
    ReactiveArmor.Description = "<font size='19'>Нанесите [1] (40% от вашей общей физической брони) всем персонажам (включая вас) в радиусе [2].</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>Восстановите 35% физической брони (+4% за Геомантию) после применения.<br><font color='46b195'>2 (требование: 5 Геомантия): </font>Получите Volatile Armor на 2 хода: 40% (+4% за Геомантию) от полученного урона по броне отражается всем в радиусе 3м. Наносит не резистивный физический и магический урон в зависимости от типа брони.<br><font color='46b195'>3 (требование: 9 Геомантия): </font>Восстановите 35% магической брони (+4% за Геомантию) после применения. Также наносит урон землей от вашей магической брони. Volatile Armor длится 4 хода.<br> </font>"

    local PoisonDart = Ext.GetStat("Projectile_PoisonDartStart")
    PoisonDart.Description = "<font size='19'>Выпустите ядовитый дротик, который пробивает цель насквозь <font color='858580' size='18' face='Averia Serif'>(аналогично «Клыку снайпера»)</font> и наносит [1] и создает поверхность яда в [2] радиусе от каждого отскока.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>Накладывает эффект <font color='B97A57'>Slowed</font> (вплоть до III уровня) на 2 хода.<br><font color='46b195'>2 (требование: 5 Геомантия): </font>Повторите базовый эффект. Накладывает 'кислоту' на 2 хода, и 'разъедание' на 1 ход.<br><font color='46b195'>3 (требование: 9 Геомантия): </font>Получите способность «Отравленный дротик x1» на 3 хода, стоимость 3 ОД, перезарядка 1 ход, выстреливает 3 снарядами.<br><font color='858580' size='18' face='Averia Serif'><br>Описания уровневых эффектов есть в дневнике.</font></font>"

