    local IncarnatePoisonDart = Ext.GetStat("Projectile_IncarnatePoisonDart")
    IncarnatePoisonDart.Description = "<font size='19'>Выпустите ядовитый дротик, который пробивает цель насквозь <font color='858580' size='18' face='Averia Serif'>(аналогично «Клыку снайпера»)</font> и наносит [1] и создает поверхность яда в [2] радиусе от каждого отскока.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>Накладывает эффект <font color='B97A57'>Slowed</font> (вплоть до III уровня) на 2 хода.<br><font color='46b195'>2 (требование: 5 Геомантия): </font>Повторите базовый эффект. Накладывает 'кислоту' на 2 хода, и 'разъедание' на 1 ход.<br><font color='46b195'>3 (требование: 9 Геомантия): </font>Получите способность «Отравленный дротик x1» на 3 хода, стоимость 3 ОД, перезарядка 1 ход, выстреливает 3 снарядами.<br><font color='858580' size='18' face='Averia Serif'><br>Описания уровневых эффектов есть в дневнике.</font></font>"

    local BallisticShot = Ext.GetStat("Projectile_BallisticShot")
    BallisticShot.Description = "<font size='19'>Выпустите особую стрелу, которая наносит (в области действия 2м) [1] +[2]% базового урона за каждый 1м до цели.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>+5% урона в момент применения за каждый 1м до цели. Накладывает эффект <font color='c82300'>Ataxia</font> (вплоть до III уровня).<br><font color='46b195'>2 (требование: 5 Мастерство охоты): </font>+15% урона в момент применения за каждый 1м до цели. Накладывает 1 <font color='c80030'>Battered</font> (+0.2 за Мастерство охоты). Восстановите 1 очко Истока.<br><font color='46b195'>3 (требование: 9 Мастерство охоты): </font>+10% шанса крит. удара в момент применения за каждый 1м до цели. Повторите базовый эффект.<br><font color='858580' size='18' face='Averia Serif'><br>Описания уровневых эффектов есть в дневнике.</font></font>"

    local PinDown = Ext.GetStat("Projectile_PinDown")
    PinDown.Description = "<font size='19'>Мощный выстрел, который наносит [1].<br><br><font color='b823cb'>Vulnerable III</font> требует 7 <font color='c80030'>Battered</font>:<br>Порча (урон от лечения). Проще наложить стаки Battered/Harried.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>Накладывает эффект 'Разрыв сухожилий' на 1 ход. +10% точности (+2% за Мастерство охоты) в момент применения.<br><font color='46b195'>2 (требование: 5 Мастерство охоты): </font>+1 ход длительности для эффекта 'Разрыв сухожилий'. Накладывает 1 <font color='c80030'>Battered</font> (+0.2 за Мастерство охоты).<br><font color='46b195'>3 (требование: 9 Мастерство охоты): </font>Накладывает эффект <font color='c82300'>Ataxia</font> (вплоть до III уровня). Способность применяется на всех видимых противников в радиусе 13м от цели. Накладывает 2 <font color='c80030'>Battered</font> (+0.2 за Мастерство охоты). Восстановите 1 очко Истока.<br><font color='858580' size='18' face='Averia Serif'><br>Описания уровневых эффектов есть в дневнике.</font></font>"

    local ArrowSpray = Ext.GetStat("Projectile_ArrowSpray")
    ArrowSpray.Description = "<font size='19'>Выпустите 16 стрел в [2]-градусном конусе, каждая стрела наносит [1].<br><br><font color='c80030'>При применении, Вихрь стрел снижает ваш множитель от мощи на 35%.</font></font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>Убирает эффект пониженного множителя от мощи.<br><font color='46b195'>2 (требование: 5 Мастерство охоты): </font>Получите способность «Вихрь стрел x1» на 1 ход, стоимостью 3 ОД и не имеющую эффекта пониженного множителя от мощи.<br><font color='46b195'>3 (требование: 9 Мастерство охоты): </font>Способность «Вихрь стрел x1» может быть применена в течение 3 ходов.<br> </font>"

    local ArrowSpray2 = Ext.GetStat("Projectile_ArrowSpray_Empowered_2")
    ArrowSpray2.Description = "<font size='19'>Выпустите 16 стрел в [2]-градусном конусе, каждая стрела наносит [1].</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>Убирает эффект пониженного множителя.<br><font color='46b195'>2 (требование: 5 Мастерство охоты): </font>Дает способность «Вихрь стрел x1» на 1 ход, стоимостью 3 ОД и не имеющую эффекта пониженного множителя от мощи.<br><font color='46b195'>3 (требование: 9 Мастерство охоты): </font>Способность «Вихрь стрел x1» может быть применена в течение 3 ходов.<br> </font>"

    local ElementalArrowheads = Ext.GetStat("Target_ElementalArrowheads")
    ElementalArrowheads.Description = "<font size='19'>Выберите поверхность и наложите на себя соответствующий ей стихийный эффект, который добавляет [1]урона (до модификаторов) для вашего лука, арбалета или жезла на 2 хода.<br><br><font color='c80030'>Не накладывается, отключается если экипировано оружие ближнего боя.</font></font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>+1 ход длительности. Восстановите 2 ОД.<br><font color='46b195'>2 (требование: 5 Мастерство охоты): </font>+1 ход длительности. Когда вы попадаете по противнику базовой атакой, наложите на него эффект, соответствующий бонусному урону от «Стрел стихий» (отравление, заряд, окаменение, сожжение, кровотечение или хрупкость). Восстановите 1 очко Истока.<br> </font>"

    local SkyShot = Ext.GetStat("Projectile_SkyShot")
    SkyShot.Description = "<font size='19'>Подпрыгните вверх и нанесите [1] целевому персонажу.<br><font color='c80030'>Заплатите до 4 ОД:</font> За каждое недостающее ОД вы получаете 2 стака <font color='c80030'>Battered</font> и <font color='188EDE'>Harried</font>.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>У вас всегда остается как минимум 1 ОД после применения. +25% урона (+4% за Мастерство охоты) в момент применения.<br><font color='46b195'>2 (требование: 5 Мастерство охоты): </font>+40% урона (+8% за Мастерство охоты) в момент применения. Примените «Ошеломляющий разряд» на вашу цель. Восстановите 2 ОД.<br><font color='46b195'>3 (требование: 9 Мастерство охоты): </font>Примените способность «Ошеломляющий разряд» на всех противников в радиусе 13м от цели.<br> </font>"

    local MarksmansFang = Ext.GetStat("Projectile_PiercingShot")
    MarksmansFang.Description = "<font size='19'>Выпустите стрелу, которая пробивает цель насквозь и наносит [1] каждой цели.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>+25% урона(+4% за Мастерство охоты) в момент применения.<br><font color='46b195'>2 (требование: 5 Мастерство охоты): </font>+20% урона (+4% за Мастерство охоты) в момент применения. При попадании, разделяется на двух ближайших видимых противников в радиусе 8м от цели.<br><font color='46b195'>3 (требование: 9 Мастерство охоты): </font>+20% урона (+4% за Мастерство охоты) в момент применения. При попадании, разделяется на всех видимых противников в радиусе 13м от цели.<br> </font>"

    local Assassinate = Ext.GetStat("Projectile_Snipe")
    Assassinate.Description = "<font size='19'>Тщательно подготовьте свой выстрел и нанесите [1].<br>При применении из скрытности наносит [2]% от базового урона.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>Противник (не Босс) умирает, если у него остается меньше здоровья, чем значение полученного от этой способности урона.<br><font color='46b195'>2 (требование: 5 Мастерство охоты): </font>Если используется из скрытности, нанесите дополнительные 200% колющего урона.<br><font color='46b195'>3 (требование: 9 Мастерство охоты): </font>Накладывает ‘Дезинтеграция: Колющий’ 25% (+2.5% за Мастерство охоты) на 1 ход. Если используется из скрытности, получите бонус +50% урона (+5% за Мастерство охоты) в момент использования и восстановите 1 очко Истока.<br> </font>"

    local Enrage = Ext.GetStat("Shout_AMER_Enrage")
    Enrage.Description = "<font size='19'>Наложите на себя эффект <font color='ffffff'>Берсерк</font>.<br>В течение своего хода, когда экипировано оружие ближнего боя:<br>- Получите +50% шанса крит. удара во время прим. способностей Военного дела.<br>- Такие крит. атаки получают 30% мультипликативного бонуса к урону.<br>- Также такая критическая атака (один раз за одно действие) отнимает у вас 20% (+1% за уровень) от вашего общего здоровья.<br>- Вы теряете доступ к вампиризму (при применении способностей Военного дела).<br>- Базовые атаки восст. 25% общ. здоровья.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>Получите <font color='11D77A'>иммунитет к эффекту Ataxia.</font> При попадании, наложите эффект <font color='ff9e9e'>Subjugated</font> (вплоть до II уровня) на противников в момент применения способностей Военного дела.<br><font color='46b195'>2 (требование: 5 Военное дело): </font>Получите <font color='11D77A'>иммунитет к эффектам Subjugated и Slowed.</font> При попадании, наложите эффект <font color='ff9e9e'>Subjugated</font> (вплоть до III уровня) и 'кровотечение' на 2 хода на противников в момент применения способностей Военного дела.<br> </font>"

    local BlitzAttack = Ext.GetStat("MultiStrike_BlinkStrike")
    BlitzAttack.Description = "<font size='19'>Перескакивайте между противниками в радиусе [2] от вашей цели, нанося [1] каждому из [3] персонажей.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>+5% точности (+1% за Военное дело) и +15% урона (+3% за Военное дело) в момент применения. Восстановите 2 ОД.<br><font color='46b195'>2 (требование: 5 Военное дело): </font>Получите способность «Блиц-атака x1» до конца вашего хода, стоимость 1 ОД, наносит на 50% больше урона, задевает до трех целей, накладывает кровотечение, кислоту и удушение на 1 ход. Получите эффект 'Стальное сердце' на 3 хода.<br><font color='46b195'>3 (требование: 9 Военное дело): </font>Способность «Блиц-атака x1» может быть применена в течение 3 ходов. Получите эффекты 'Огненное клеймо' и 'Огниво' на 3 хода.<br><font color='858580' size='18' face='Averia Serif'><br>Описания уровневых эффектов есть в дневнике.</font></font>"

    local BlitzAttack2 = Ext.GetStat("MultiStrike_BlinkStrike_Empowered_2")
    BlitzAttack2.Description = "<font size='19'>Перескакивайте между противниками в радиусе [2] от вашей цели, нанося [1] каждому из [3] персонажей.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>+5% точности (+1% за Военное дело) и +15% урона (+3% за Военное дело) в момент применения. Восстановите 2 ОД.<br><font color='46b195'>2 (требование: 5 Военное дело): </font>Получите способность «Блиц-атака x1» до конца вашего хода, стоимость 1 ОД, наносит на 50% больше урона, задевает до трех целей, накладывает кровотечение, кислоту и удушение на 1 ход. Получите эффект 'Стальное сердце' на 3 хода.<br><font color='46b195'>3 (требование: 9 Военное дело): </font>Способность «Блиц-атака x1» может быть применена в течение 3 ходов. Получите эффекты 'Огненное клеймо' и 'Огниво' на 3 хода.<br><font color='858580' size='18' face='Averia Serif'><br>Описания уровневых эффектов есть в дневнике.</font></font>"

    local BouncingShield = Ext.GetStat("Projectile_BouncingShield")
    BouncingShield.Description = "<font size='19'>Бросьте свой щит, который рикошетит в одного противника в [2] радиусе и наносит [1] обоим. </font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>Перед применением, восстановите себе значение брони в соответствии со значениями щита. <br><font color='46b195'>2 (требование: 5 Военное дело): </font>Повторите базовый эффект.<br><font color='46b195'>3 (требование: 9 Военное дело): </font>Применяется на всех противников в радиусе 13м.<br> </font>"

    local ArenaBouncingShield = Ext.GetStat("Projectile_BouncingShield_TheArena")
    ArenaBouncingShield.Description = "<font size='19'>Бросьте свой щит в противника, который рикошетит в двух противников в [2] радиусе и наносит [1] каждой цели. </font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>Перед применением, восстановите себе значение брони в соответствии со значениями щита. <br><font color='46b195'>2 (требование: 5 Военное дело): </font>Повторите базовый эффект.<br><font color='46b195'>3 (требование: 9 Военное дело): </font>Применяется на всех противников в радиусе 13м.<br> </font>"

    local SparkingSwings = Ext.GetStat("Shout_SparkingSwings")
    SparkingSwings.Description = "<font size='19'>Наложите на себя эффект <font color='ffffff'>Искры</font>, с которым персонаж будет высекать огненные искры при атаках ближнего боя, отскакивающие в ближайшего противника в радиусе 13м от цели, нанося [1] и накладывая 'сожжение' на 1 ход.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>Эффект становится 5м аурой. +1 ход длительности.<br><font color='46b195'>2 (требование: 5 Пирокинетика): </font>+1 дополнительный отскок искр. Радиус ауры теперь 8м. Восстановите 1 очко Истока.<br><font color='46b195'>3 (требование: 9 Пирокинетика): </font>+1 дополнительный отскок искр. +2 хода длительности. Радиус ауры теперь 13м.<br> </font>"

    local PyroTrap = Ext.GetStat("Projectile_LaunchExplosiveTrap")
    PyroTrap.Description = "<font size='19'>Бросьте взрывную ловушку, которая активируется на ваш следующий ход. После установки, когда противник оказывается в радиусе [2] от ловушки, она взрывается и наносит персонажам [1]. Урон зависит от параметров бросившего ее персонажа, ловушка не активируется вне боя и в бою ее нельзя активировать до завершения установки.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>Получите способность «Взрывная ловушка x1» стоимостью 0 ОД до конца вашего хода.<br><font color='46b195'>2 (требование: 5 Пирокинетика): </font>Получите способность «Взрывная ловушка x2», которая бросает 3 ловушки.<br><font color='46b195'>3 (требование: 9 Пирокинетика): </font>Способность «Взрывная ловушка x2» может быть применена в течение 2 ходов, перезарядка 1 ход. Восстановите 1 очко Истока.<br> </font>"

    local Supernova = Ext.GetStat("Shout_Supernova")
    Supernova.Description = "<font size='19'>Получите +40% сопротивления огню перед применением. Создает огненную поверхность и наносит [1] себе и всем персонажам в [2] радиусе вокруг вас.<br>Если вы умрете при применении этой способности, она нанесет [3] персонажам в радиусе 8м.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>+25% урона (+4% за Пирокинетику) в момент применения.<br><font color='46b195'>2 (требование: 5 Пирокинетика): </font>+40% урона (+8% за Пирокинетику) в момент применения. Восстановите 2 ОД.<br><font color='46b195'>3 (требование: 9 Пирокинетика): </font>«Сверхновая» применяется вновь на каждом задетом противнике (наносит урон только противникам).<br> </font>"

    local EpidemicOfFire = Ext.GetStat("Projectile_InfectiousFlame")
    EpidemicOfFire.Description = "<font size='19'>Наложите <font color='ffffff'>Эпидемию огня</font> на целевого персонажа, которая наносит [1] и также повторяет этот урон в начале каждого хода цели в радиусе 3м вокруг нее.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>+1 ход длительности.<br><font color='46b195'>2 (требование: 5 Пирокинетика): </font>Урон от эффекта 'Эпидемия огня' накладывает эффекты <font color='639594'>Weakened</font> и <font color='7F25D4'>Terrified</font> (вплоть до III уровня) на 1 ход. +1 ход длительности.<br><font color='46b195'>3 (требование: 9 Пирокинетика): </font>Эффект 'Эпидемия огня' распространяется на персонажей в радиусе 5м.<br><font color='858580' size='18' face='Averia Serif'><br>Описания уровневых эффектов есть в дневнике.</font></font>"

    local IncarnateEpidemicOfFire = Ext.GetStat("Projectile_IncarnateInfectiousFlame")
    IncarnateEpidemicOfFire.Description = "<font size='19'>Наложите <font color='ffffff'>Эпидемию огня</font> на целевого персонажа, которая наносит [1] и также повторяет этот урон в начале каждого хода цели в радиусе 3м вокруг нее.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>+1 ход длительности.<br><font color='46b195'>2 (требование: 5 Пирокинетика): </font>Эффект 'Эпидемия огня' накладывает эффекты <font color='639594'>Weakened</font> и <font color='7F25D4'>Terrified</font> (вплоть до III уровня) на 1 ход. +1 ход длительности.<br><font color='46b195'>3 (требование: 9 Пирокинетика): </font>Эффект 'Эпидемия огня' распространяется на персонажей в радиусе 5м.<br><font color='858580' size='18' face='Averia Serif'><br>Описания уровневых эффектов есть в дневнике.</font></font>"

    local Bloodlust = Ext.GetStat("Shout_ThickOfTheFight")
    Bloodlust.Description = "<font size='19'>Наложите на себя эффект <font color='ffffff'>Гуща битвы</font>, который дает +[1]% урона за каждого персонажа в [2] радиусе вокруг вас.<br><font color='c80030'>Заплатите до X ОД:</font> X означает количество персонажей в области действия способности: За каждое недостающее ОД вы получаете 2 стака <font color='c80030'>Battered</font> и <font color='188EDE'>Harried</font>.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>У вас всегда остается как минимум 1 ОД после применения. Эмулируйте эффект способности «Смерч» в радиусе 5м.<br><font color='46b195'>2 (требование: 5 Военное дело): </font>Когда вы применяете базовую атаку на противника, при попадании, наложите эффект <font color='639594'>Weakened</font> (вплоть до III уровня) на 2 хода. Получите талант 'Живой доспех' на 2 хода. Восстановите 1 очко Истока.<br><font color='46b195'>3 (требование: 9 Военное дело): </font>Один раз за раунд (один раз на одну цель) при применении базовой атаки, примените «Сокрушающий удар» на задетых персонажей и восстановите 2 ОД.<br><font color='858580' size='18' face='Averia Serif'><br>Описания уровневых эффектов есть в дневнике.</font></font>"

    local Immolation = Ext.GetStat("Target_FlamingCrescendo")
    Immolation.Description = "<font size='19'>Наложите эффект <font color='ffffff'>Огненное извержение</font> на целевого персонажа, который срабатывает при окончании действия или когда цель умирает, нанося [1] персонажам в 3м радиусе.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>Базовый урон взрыва увеличен на 40% и теперь наносит урон только противникам.<br><font color='46b195'>2 (требование: 5 Пирокинетика): </font>Также применяется на ближайшего видимого противника в радиусе 13м от вас. Восстановите 1 очко Истока.<br><font color='46b195'>3 (требование: 9 Пирокинетика): </font>Вместо предыдущих бонусов насыщения Истоком: накладывает 'Огненное извержение' на 3 хода на всех противников в радиусе 13м. Каждый ход оно взрывается с повышенным уроном (от насыщения Истоком 1) в радиусе 3м вокруг цели.<br> </font>"

    local ArmorOfFrost = Ext.GetStat("Target_FrostyShell")
    ArmorOfFrost.Description = "<font size='19'>Божественный лед покрывает цель и дает [1].<br><font color='6CCBFF'>Очищает сожжение, заряд, окаменение, отравление, удушение, чуму, Dazzled и Squelched.</font></font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>Дает и восстанавливает +10% общей магической брони(+1% за Гидрософистику).<br><font color='46b195'>2 (требование: 5 Гидрософистика): </font>Накладывается на всех союзников в радиусе 13м.<br><font color='46b195'>3 (требование: 9 Гидрософистика): </font>Дает и восстанавливает +2% общей магической брони за Гидрософистику. Дает +10% Сопротивления стихиям (+1.5% за Гидрософистику). <font color='6CCBFF'>Снимает 1 стак Harried</font> (+0.3 за Гидрософистику). Восстановите 1 очко Истока.<br> </font>"

    local WinterBlast = Ext.GetStat("Target_WinterBlast")
    WinterBlast.Description = "<font size='19'>Нанесите [1] противникам в [2] радиусе и создайте там поверхность льда.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>+10% урона (+2% за Гидрософистику) в момент применения. Накладывает 1 <font color='188EDE'>Harried</font> (+0.2 за Гидрософистику).<br><font color='46b195'>2 (требование: 5 Гидрософистика): </font>Усиливает снижение сопротивлений от уровневых эффектов на 15% (+2% за Гидрософистику) на 2 хода.<br><font color='46b195'>3 (требование: 9 Гидрософистика): </font>Используйте аналог способности «Пролом льда» (75% множитель) в области действия. Получите способность «Взрыв стужи x1» на 3 хода, которая использует аналог способности «Пролом льда», наносит на 50% больше урона и имеет перезарядку 1 ход.<br> </font>"

    local EmpoweredWinterBlast = Ext.GetStat("Target_WinterBlast_Empowered")
    EmpoweredWinterBlast.Description = "<font size='19'>Нанесите [1] противникам в [2] радиусе и создайте там поверхность льда.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>+10% урона (+2% за Гидрософистику) в момент применения. Накладывает 1 <font color='188EDE'>Harried</font> (+0.2 за Гидрософистику).<br><font color='46b195'>2 (требование: 5 Гидрософистика): </font>Усиливает снижение сопротивлений от уровневых эффектов на 15% (+2% за Гидрософистику) на 2 хода.<br><font color='46b195'>3 (требование: 9 Гидрософистика): </font>Используйте аналог способности «Пролом льда» (75% множитель) в области действия. Получите способность «Взрыв стужи x1» на 3 хода, которая использует аналог способности «Пролом льда», наносит на 50% больше урона и имеет перезарядку 1 ход.<br> </font>"

    local FanOfKnives = Ext.GetStat("Projectile_FanOfKnives")
    FanOfKnives.Description = "<font size='19'>Метните кинжал во всех противников в [2] радиусе вокруг вас, нанося [1].</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>+5% точности (+1% за Искусство убийства). +25% урона (+4% за Искусство убийства) в момент применения.<br><font color='46b195'>2 (требование: 5 Искусство убийства): </font>Повторите базовый эффект. +40% урона (+8% за Искусство убийства) в момент применения. Войдите в скрытность до применения.<br><font color='46b195'>3 (требование: 9 Искусство убийства): </font>Получите способность «Веер ножей x1» на 3 хода, стоимость 3 ОД, перезарядка 1 ход, наносит на 50% больше урона и кинжалы дополнительно отскакивают в противников в радиусе 8м.<br> </font>"

    local EmpoweredFanOfKnives = Ext.GetStat("Projectile_FanOfKnives_Empowered")
    EmpoweredFanOfKnives.Description = "<font size='19'>Метните кинжал во всех противников в [2] радиусе вокруг вас, нанося [1] и отскакивая в противника в радиусе 8м.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>+5% точности (+1% за Искусство убийства). +25% урона (+4% за Искусство убийства) в момент применения.<br><font color='46b195'>2 (требование: 5 Искусство убийства): </font>Повторите базовый эффект. +40% урона (+8% за Искусство убийства) в момент применения. Войдите в скрытность до применения.<br><font color='46b195'>3 (требование: 9 Искусство убийства): </font>Получите способность «Веер ножей x1» на 3 хода, стоимость 3 ОД, перезарядка 1 ход, наносит на 50% больше урона и кинжалы дополнительно отскакивают в противников в радиусе 8м.<br> </font>"

    local ThrowingKnife = Ext.GetStat("Projectile_ThrowingKnife")
    ThrowingKnife.Description = "<font size='19'>Метните нож в целевого персонажа, который наносит [1]. </font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>+5% точности (+1% за Искусство убийства) и +15% урона (+3% за Искусство убийства) в момент применения. Восстановите 2 ОД.<br><font color='46b195'>2 (требование: 5 Искусство убийства): </font>Повторите базовый эффект. Если применяется из скрытности, получите +40% урона (+8% за Искусство убийства) в момент применения.<br><font color='46b195'>3 (требование: 9 Искусство убийства): </font>+4 броска кинжала. Если применяется из скрытности, получите способность «Метательный нож x1» на 3 хода, стоимость 3 ОД, перезарядка 1 ход, отлетает в двух противников в радиусе 8м.<br> </font>"

    local EmpoweredThrowingKnife = Ext.GetStat("Projectile_ThrowingKnife_Empowered")
    EmpoweredThrowingKnife.Description = "<font size='19'>Метните нож в целевого персонажа, который наносит [1]. </font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>+5% точности (+1% за Искусство убийства) и +15% урона (+3% за Искусство убийства) в момент применения. Восстановите 2 ОД.<br><font color='46b195'>2 (требование: 5 Искусство убийства): </font>Повторите базовый эффект. Если применяется из скрытности, получите +40% урона (+8% за Искусство убийства) в момент применения.<br><font color='46b195'>3 (требование: 9 Искусство убийства): </font>+4 броска кинжала. Если применяется из скрытности, получите новую способность 'Метательный нож' на 3 хода, стоимость 3 ОД, перезарядка 1 ход, отлетает в двух противников в радиусе 8м.<br> </font>"

    local TerifyingCruelty = Ext.GetStat("Target_TerrifyingCruelty")
    TerifyingCruelty.Description = "<font size='19'>Удар в [2] области наносит [1] каждому.<br><br><font color='ff9e9e'>Subjugated III</font> требует 7 <font color='c80030'>Battered</font>:<br>Уменьшенная вероятность нападения на владельца эффекта (при атаке получает урон водой), штраф к восстановлению ОД.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>+25% урона (+4% за Искусство убийства) в момент применения.<br><font color='46b195'>2 (требование: 5 Искусство убийства): </font>Накладывает 'Разрыв сухожилий' на 1 ход. Накладывает 1 <font color='c80030'>Battered</font> (+0.2 за Искусство убийства).<br><font color='46b195'>3 (требование: 9 Искусство убийства): </font>Повторите базовый эффект на противников в радиусе 5м от вас. Если применяется из скрытности, восстановите 1 ОД и получите бонус +40% урона (+8% за Искусство убийства) в момент применения.<br><font color='858580' size='18' face='Averia Serif'><br>Описания уровневых эффектов есть в дневнике.</font></font>"

    local IncarnateTerifyingCruelty = Ext.GetStat("Target_IncarnateTerrifyingCruelty")
    IncarnateTerifyingCruelty.Description = "<font size='19'>Удар в [2] области наносит [1] каждому.<br><br><font color='ff9e9e'>Subjugated III</font> требует 7 <font color='c80030'>Battered</font>:<br>Уменьшенная вероятность нападения на владельца эффекта (при атаке получает урон водой), штраф к восстановлению ОД.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>+25% урона (+4% за Искусство убийства) в момент применения.<br><font color='46b195'>2 (требование: 5 Искусство убийства): </font>Накладывает 'Разрыв сухожилий' на 1 ход. Накладывает 1 <font color='c80030'>Battered</font> (+0.2 за Искусство убийства).<br><font color='46b195'>3 (требование: 9 Искусство убийства): </font>Повторите базовый эффект на противников в радиусе 5м от вас. Если применяется из скрытности, восстановите 1 ОД и получите бонус +40% урона (+8% за Искусство убийства) в момент применения.<br><font color='858580' size='18' face='Averia Serif'><br>Описания уровневых эффектов есть в дневнике.</font></font>"
    
    local Infect = Ext.GetStat("Target_Infect")
    Infect.Description = "<font size='19'>Нанесите [1].<br><br><font color='639594'>Weakened III</font> требует 7 <font color='c80030'>Battered</font>:<br>Значительное снижение урона.<br><font color='7F25D4'>Terrified III</font> требует 7 <font color='188EDE'>Harried</font>:<br>Отключение атак по возможности, нельзя обнаружить персонажей в скрытности и трата ОД от устрашения.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>+10% урона (+2.5% за Некромантию) за труп в радиусе 13м, в момент применения. Восстановите 1 ОД.<br><font color='46b195'>2 (требование: 5 Некромантия): </font>+25% урона (+4% за Некромантию) за труп в радиусе 13м, в момент применения. Накладывает 3 <font color='c80030'>Battered</font> (+0.4 за Некромантию).<br><font color='46b195'>3 (требование: 9 Некромантия): </font>За каждый труп в радиусе 13м, повторите базовый эффект на противников, находящихся в радиусе 5м от этих трупов.<br><font color='858580' size='18' face='Averia Serif'><br>Описания уровневых эффектов есть в дневнике.</font></font>"

    local GraspOfTheStarved = Ext.GetStat("Target_GraspOfTheStarved")
    GraspOfTheStarved.Description = "<font size='19'>Призовите спектральные руки, которые разрывают ваших противников, нанося [1] тем, кто стоит на крови или находится под эффектом кровотечения.<br><br><font color='639594'>Weakened III</font> требует 7 <font color='c80030'>Battered</font>:<br>Значительное снижение урона.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>+10% урона (+2.5% за Некромантию) за труп в области действия, в момент применения.<br><font color='46b195'>2 (требование: 5 Некромантия): </font>Перед применением, замените все поверхности и облака и создайте поверхность крови в области применения. Накладывает 2 <font color='c80030'>Battered</font> (+0.3 за Некромантию, за труп в области действия).<br><font color='46b195'>3 (требование: 9 Некромантия): </font>Повторите базовый эффект. +25% урона (+4% за Некромантию) за труп в области действия, в момент применения. Если в области применения есть 3 или больше трупов, повторите базовый эффект еще раз.<br><font color='858580' size='18' face='Averia Serif'><br>Описания уровневых эффектов есть в дневнике.</font></font>"

    local HorridWilting = Ext.GetStat("Target_AMER_HorridWilting")
    HorridWilting.Description = "<font size='19'>Нанесите [1] противникам в [2] области применения. Цели получают на 50% больше урона водой, если у них нет физической брони и 50% физического урона, если у них нет магической брони.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>Наложите эффект <font color='b823cb'>Vulnerable</font> (вплоть до III уровня) на 2 хода.<br><font color='46b195'>2 (требование: 5 Некромантия): </font>+40% урона (+8% за Некромантию) в момент применения. Дополнительный урон от недостающей брони теперь наносится, когда ее меньше 50%.<br><font color='46b195'>3 (требование: 9 Некромантия): </font>+40% урона (+8% за Некромантию) в момент применения. Множитель дополнительного урона 150%. Детонирует 'хрупкость' на задетых противниках.<br><font color='858580' size='18' face='Averia Serif'><br>Описания уровневых эффектов есть в дневнике.</font></font>"

    local Adrenaline = Ext.GetStat("Shout_Adrenaline")
    Adrenaline.Description = "<font size='19'>Наложите на себя эффект <font color='ffffff'>Адреналин</font>, который немедленно дает вам 4 ОД, но забирает 6 ОД на следующем ходу.<font color='858580' size='18' face='Averia Serif'><br><br>Не даёт ОД выше лимита.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>Получите дополнительные 2 ОД и наложите на себя 'Ускорение' на 1 ход.<br><font color='46b195'>2 (требование: 5 Искусство убийства): </font>Получите +20% инвестированной мощи (+2% за Искусство убийства) на 2 хода.<br><font color='46b195'>3 (требование: 9 Искусство убийства): </font>Получите дополнительные 4 ОД.<br> </font>"

    local ChameleonCloak = Ext.GetStat("Shout_ChameleonSkin")
    ChameleonCloak.Description = "<font size='19'>Войдите в скрытность, получите невидимость до конца своего хода и эффект <font color='ffffff'>Покров хамелеона</font>, который дает +5 к скрытности.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>Восстановите 2 ОД. +1 ход длительности.<br><font color='46b195'>2 (требование: 5 Превращение): </font>Вы пытаетесь войти в скрытность в конце своего хода. +1 ход длительности. Восстановите 1 очко Истока.<br><font color='46b195'>3 (требование: 9 Превращение): </font>В начале хода вы входите в скрытность и получаете невидимость до конца своего хода. +1 ход длительности.<br> </font>"

    local DeflectiveBarrier = Ext.GetStat("Shout_DeflectiveBarrier")
    DeflectiveBarrier.Description = "<font size='19'>Наложите на себя эффект <font color='ffffff'>Отражающий барьер</font>, который дает [1], <font color='11D77A'>иммунитет к телепортации</font> и также отражает летящие в радиусе 1м от вас снаряды обратно в атакующего.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>Наложите эффект 'Провокация' на всех противников в радиусе 5м вокруг вас.<br><font color='46b195'>2 (требование: 5 Военное дело): </font>Союзники в радиусе 13м, у которых есть как минимум 1 очко Гидрософистики, бесплатной реакцией ритуала используют на вас «Ритуал исцеления».<br><font color='46b195'>3 (требование: 9 Военное дело): </font>Накладывается на всех союзников в радиусе 13м. Восстановите 1 очко Истока.<br> </font>"

    local SteamLance = Ext.GetStat("Cone_SteamLance")
    SteamLance.Description = "<font size='19'>Создайте пары воды, которые <font color='6CCBFF'>очищают Weakened, Vulnerable, хрупкость и чуму</font> с союзников в [4]-градусном [3] конусе и накл. эффект <font color='b823cb'>Vulnerable</font> (вплоть до III уровня) на противников. Восстанавливает [1] в течение 3х союзникам (не получающим урон от лечения) и противникам (получающим урон от лечения) и наносит [2] противникам.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>+15% урона (+2% за Гидрософистику) в момент применения. Накладывает 2 стака <font color='c80030'>Battered</font>(+0.2 за Гидрософистику) на врагов.<br><font color='46b195'>2 (требование: 5 Гидрософистика): </font>Накладывает ‘Магический панцирь’ и ‘Ускорение’ на союзников на 3 хода. Накладывает 2 стака <font color='c80030'>Battered</font> (+0.2 за Гидрософистику) на противников. Получите «Паровое копье x1» стоимостью 2 ОД на 1 ход.<br><font color='46b195'>3 (требование: 9 Гидрософистика): </font>+40% урона (+8% за Гидрософистику) в момент применения. «Паровое копье x1» может быть применено в течение 4 ходов. Союзники в радиусе 13м от цели, у которых есть как минимум 1 очко Гидрософистики, бесплатной реакцией ритуала применяют «Паровое копье» на вашу цель. За каждого участника ритуала получите по +3% урона за Гидрософистику.<br> </font>"

    local EmpoweredSteamLance = Ext.GetStat("Cone_SteamLance_Empowered")
    EmpoweredSteamLance.Description = "<font size='19'>Создайте пары воды, которые <font color='6CCBFF'>очищают Weakened, Vulnerable, хрупкость и чуму</font> с союзников в [4]-градусном [3] конусе и накл. эффект <font color='b823cb'>Vulnerable</font> (вплоть до III уровня) на противников. Восстанавливает [1] в течение 3х союзникам (не получающим урон от лечения) и противникам (получающим урон от лечения) и наносит [2] противникам.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>+15% урона (+2% за Гидрософистику) в момент применения. Накладывает 2 стака <font color='c80030'>Battered</font>(+0.2 за Гидрософистику) на врагов.<br><font color='46b195'>2 (требование: 5 Гидрософистика): </font>Накладывает ‘Магический панцирь’ и ‘Ускорение’ на союзников на 3 хода. Накладывает 2 стака <font color='c80030'>Battered</font> (+0.2 за Гидрософистику) на противников. Получите «Паровое копье x1» стоимостью 2 ОД на 1 ход.<br><font color='46b195'>3 (требование: 9 Гидрософистика): </font>+40% урона (+8% за Гидрософистику) в момент применения. «Паровое копье x1» может быть применено в течение 4 ходов. Союзники в радиусе 13м от цели, у которых есть как минимум 1 очко Гидрософистики, бесплатной реакцией ритуала применяют «Паровое копье» на вашу цель. За каждого участника ритуала получите по +3% урона за Гидрософистику.<br> </font>"

    local Vault1 = Ext.GetStat("MultiStrike_Vault")
    Vault1.Description = "<font size='19'>Телепортируйте за спину цели и нанесите [1].</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>+5% точности (+1% за Искусство убийства) и +15% урона (+3% за Искусство убийства) в момент применения. Восстановите 2 ОД.<br><font color='46b195'>2 (требование: 5 Искусство убийства): </font>+40% урона (+8% за Искусство убийства) в момент применения. Накладывает на вас невидимость до конца хода.<br><font color='46b195'>3 (требование: 9 Искусство убийства): </font>Повторите базовый эффект 2 раза. Получите способность «Грязный прием x1» на 3 хода, перезарядка 1 ход, Если способность «Грязный прием x1» используется из скрытности, ее дальность составляет 13м и она стоит 2 ОД.<br> </font>"

