    Vault3.Description = "<font size='19'>Телепортируйте за спину цели и нанесите [1].</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>+5% точности (+1% за Искусство убийства) и +15% урона (+3% за Искусство убийства) в момент применения. Восстановите 2 ОД.<br><font color='46b195'>2 (требование: 5 Искусство убийства): </font>+40% урона (+8% за Искусство убийства) в момент применения. Накладывает на вас невидимость до конца хода.<br><font color='46b195'>3 (требование: 9 Искусство убийства): </font>Повторите базовый эффект 2 раза. Получите способность «Грязный прием x1» на 3 хода, перезарядка 1 ход, Если способность «Грязный прием x1» используется из скрытности, ее дальность составляет 13м и она стоит 2 ОД.<br> </font>"

    local SpiderLegs = Ext.GetStat("Shout_SpiderLegs")
    SpiderLegs.Description = "<font size='19'>Наложите на себя эффект <font color='ffffff'>Паучьи ноги</font>, который дает вам ускорение, когда вы находитесь на паутине и способность «Плетение паутины», которая создает поверхность паутины и накладывает эффект <font color='B97A57'>Slowed</font> (вплоть до III уровня) на противников в 3м области действия.<br><br><font color='c80030'>Несовместимо со «Взмахом крыльев».</font></font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>Способность «Плетение паутины» наносит [1] и накладывает 'окаменение' на 2 хода.<br><font color='46b195'>2 (требование: 5 Превращение): </font>Урон от способности «Плетение паутины» увеличен на 100% и также она накладывает кислоту, удушение и разъедание на 1 ход. Восстановите 1 очко Истока.<br><font color='46b195'>3 (требование: 9 Превращение): </font>Способность «Плетение паутины» выстреливает 3 снарядами, каждый из которых наносит 40% от базового урона способности. +2 хода длительности. Восстановите 2 ОД.<br> </font>"

    local MedusaHead = Ext.GetStat("Shout_MedusaHead")
    MedusaHead.Description = "<font size='19'>Наложите на себя эффект <font color='ffffff'>Голова медузы</font>, который дает +[1]% сопротивления земле и ауру, которая накладывает <font color='B97A57'>Slowed</font> I на противников в [2] радиусе. Получите способность «Окаменяющий лик», которая наносит урон землей противникам в радиусе 13м, накладывает 'окаменение' и эффект <font color='ff9e9e'>Subjugated</font> (вплоть до II уровня).<br><br><font color='c80030'>Несовместимо с «Бычьими рогами».</font></font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>Способность «Окаменяющий лик» применяется сразу.<br><font color='46b195'>2 (требование: 5 Превращение): </font>+1 ход длительности. Способность «Окаменяющий лик» теперь стоит 3 ОД и перезаряжается 1 ход. Восстановите 1 очко Истока.<br><font color='46b195'>3 (требование: 9 Превращение): </font>Способность «Окаменяющий лик» применяется в начале каждого вашего хода и теперь стоит 2 ОД. Восстановите 2 ОД.<br><font color='858580' size='18' face='Averia Serif'><br>Описания уровневых эффектов есть в дневнике.</font></font>"

    local BullHorns = Ext.GetStat("Shout_BullHorns")
    BullHorns.Description = "<font size='19'>Наложите на себя эффект <font color='ffffff'>Бычьи рога</font>, который дает +0.5 движения и способность «Бычий натиск», которая позволяет вам мчаться вперед на расстояние до 12м, накладывая 'кровотечение' на противников.<br><br><font color='c80030'>Несовместимо с «Головой медузы».</font></font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>Урон способности «Бычий натиск» увеличен на 20%. Эффект 'Бычьи рога' дает +20% урона.<br><font color='46b195'>2 (требование: 5 Превращение): </font>Урон способности «Бычий натиск» увеличен на 20%, она стоит на 1 ОД меньше и накладывает 1 <font color='c80030'>Battered</font>. Восстановите 1 очко Истока.<br><font color='46b195'>3 (требование: 9 Превращение): </font>Урон способности «Бычий натиск» увеличен на 20%, она стоит на 1 ОД меньше и имеет повышенную на 1м область действия. Эффект 'Бычьи рога' дает +10% урона.<br> </font>"

    local ElementalInfusion = Ext.GetStat("Target_AMER_ElementalInfusion")
    ElementalInfusion.Description = "<font size='19'>Выберите поверхность в радиусе 13м, и наложите ее насыщение на вашего инкарната, которое дает +100% сопротивления (кровь дает +25% физических) и иммунитет к статусу/способность:</font><font size='17'><br><font color='ffffff'>- Вода/лед</font>: хрупкость/«Град».<br><font color='ffffff'>- Огонь</font>: сожжение/«Огненный шар».<br><font size='15'>- <font color='ffffff'>Электричество</font>: заряд/«Ошеломляющий разряд».</font><br><font size='15'><font color='ffffff'>- Нефть</font>: Slowed и окаменение/«Пронзание».</font><br><font color='ffffff'>- Яд</font>: отравление/«Отравленный дротик».<br><font color='ffffff'>- Кровь</font>: кровотечение/«Рой москитов».</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>Накладывает проклятую, благословенную версию насыщения (даже без проклятой, благословенной поверхности). Инкарнат получит способность:<br><font size='16'><font color='ffffff'>- Благословенный лед</font>: «Глубокая заморозка».<br><font color='ffffff'>- Проклятое электричество</font>: «Аура вакуума».<br><font color='ffffff'>- Некропламя</font>: «Эпидемия огня».<br><font color='ffffff'>- Проклятая нефть</font>: «Едкие брызги».<br><font color='ffffff'>- Кислота</font>: «Кислотные споры».<br><font color='ffffff'>- Проклятая кровь</font>: «Заражение».</font><br><font color='46b195'>2 (требование: 5 Призывание): </font>Получите способность «Стихийное насыщение x1» до конца вашего хода, стоимость 0 ОД, позволяет наложить второе благословенное/проклятое насыщение и дает способности, которые не имеют общей перезарядки с предыдущими. Восстановите 1 очко Истока.<br> </font>"

    local CripplingBlow = Ext.GetStat("Target_CripplingBlow")
    CripplingBlow.Description = "<font size='19'>Нанесите [1] противникам в [2] радиусе.<br><br><font color='c82300'>Ataxia III</font> требует 7 <font color='c80030'>Battered</font>:<br>Истощение (обезоружение), замедление и снижение уклонения.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>+5% точности (+1% за Военное дело) и 25% урона (+4% за Военное дело) в момент применения. <br><font color='46b195'>2 (требование: 5 Военное дело): </font>+40% урона (+8% за Военное дело) в момент применения. Повторите базовый эффект. Восстановите 2 ОД.<br><font color='46b195'>3 (требование: 9 Военное дело): </font>Повторите базовый эффект. Союзники в радиусе 13м от цели, у которых есть как минимум 1 очко Некромантии, бесплатной реакцией ритуала используют «Заражение» на вашей цели. За каждого участника ритуала получите по +3% урона за Военное дело.<br><font color='858580' size='18' face='Averia Serif'><br>Описания уровневых эффектов есть в дневнике.</font></font>"

    local FleshSacrifice = Ext.GetStat("Shout_FleshSacrifice")
    FleshSacrifice.Description = "<font size='19'>Пожертвуйте 10% от вашего максимального здоровья, получите 1 ОД и создайте под собой поверхность крови.<font color='858580' size='18' face='Averia Serif'><br><br>Не даёт ОД выше лимита.</font>"

    local SpontaneousCombustion = Ext.GetStat("Target_SpontaneousCombustion")
    SpontaneousCombustion.Description = "<font size='19'>Наносит [1] целевому персонажу. Если цель под эффектом 'сожжение', нанесите дополнительный урон за каждый оставшийся ход его действия.<br><br><font color='7F25D4'>Terrified III</font> требует 7 <font color='188EDE'>Harried</font>:<br>Отключение атак по возможности, нельзя обнаружить персонажей в скрытности и трата ОД от устрашения.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>Накладывает 1 стак <font color='c80030'>Battered</font> и <font color='188EDE'>Harried</font> за каждый ход 'сожжения' у цели.<br><font color='46b195'>2 (требование: 5 Пирокинетика): </font>Накладывает 'сожжение' на 4 хода перед применением. Накладывает 'Дезинтеграция: Огонь' 25% (+2.5% за Пирокинетику) в момент применения: при окончании эффекта противник получает процентный урон от общего полученного урона за время действия эффекта (урон огнем).<br><font color='46b195'>3 (требование: 9 Пирокинетика): </font>'Дезинтеграция' длится 1 ход и вызывает взрывы 'сожжения' при их наложении (аналогичные срабатыванию этой способности).<br><font color='858580' size='18' face='Averia Serif'><br>Описания уровневых эффектов есть в дневнике.</font></font>"

    local SearingDaggers = Ext.GetStat("Projectile_FlamingDaggers")
    SearingDaggers.Description = "<font size='19'>Метните огненные кинжалы в [3] целевые области, каждый из которых наносит [1] в [2] радиусе.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>+25% урона (+4% за Пирокинетику) в момент применения.<br><font color='46b195'>2 (требование: 5 Пирокинетика): </font>+40% урона (+8% за Пирокинетику) в момент применения. Метните дополнительный кинжал в каждую цель.<br><font color='46b195'>3 (требование: 9 Пирокинетика): </font>Союзники в радиусе 13м, у которых есть как минимум 1 очко Пирокинетики, бесплатной реакцией ритуала используют «Пылающие кинжалы» на всех видимых противников в радиусе 13м от них. За каждого участника ритуала получите +3% урона за Пирокинетику в момент применения.<br> </font>"

    local FlamingTongues = Ext.GetStat("Shout_FlamingTongues")
    FlamingTongues.Description = "<font size='19'>Наложите на себя эффект <font color='ffffff'>Языки пламени</font>, который наносит урон противникам в начале вашего хода и когда они вошли или передвинулись в [2] радиусе вокруг вас. Такие срабатывания накладывают 'сожжение' и наносят [1] цели и в области 1м вокруг нее.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>+25% урона. Накладывает 1 стак <font color='188EDE'>Harried</font> на задетых противников. +1 ход длительности.<br><font color='46b195'>2 (требование: 5 Пирокинетика): </font>+25% урона. +1 цепное срабатывание на противников в радиусе 5м. Восстановите 1 очко Истока.<br><font color='46b195'>3 (требование: 9 Пирокинетика): </font>+25% урона. +1 цепное срабатывание. Накладывает 2 стака <font color='c80030'>Battered</font> на задетых противников.<br> </font>"

    local SkinGraft = Ext.GetStat("Shout_ShedSkin")
    SkinGraft.Description = "<font size='19'><font color='6CCBFF'>Снимите с себя 3 стака Battered и Harried (+0.35 за Превращение).<br>Очищает кровотечение, сожжение, отравление, Subjugated, Weakened, Dazzled и Slowed.</font></font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>Получите эффект на 2 хода: вы сбрасываете перезарядку всех способностей боевого умения (кроме Превращения) следующей примененной вами способности, при этом снижая всю вашу броню до нуля, после чего эффект исчезает.<br><font color='46b195'>2 (требование: 5 Превращение): </font><font color='c80030'>Заплатите на 2 ОД больше:</font> Сбрасывает перезарядку всех способностей, без снижения брони до нуля.<br> </font>"

    local Ignition = Ext.GetStat("Shout_Ignition")
    Ignition.Description = "<font size='19'>Нанесите [1] противникам и подожгите/расплавьте поверхности и облака в [2] радиусе вокруг вас.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>Повторите базовый эффект.<br><font color='46b195'>2 (требование: 5 Пирокинетика): </font>Получите способность «Возгорание x1» на 3 хода.<br><font color='46b195'>3 (требование: 9 Пирокинетика): </font>Союзники в радиусе 15м, у которых есть как минимум 1 очко Пирокинетики, бесплатной реакцией ритуала используют «Возгорание». За каждого участника ритуала повторите базовый эффект 2 раза (не накладывает 'сожжение').<br> </font>"

    local EmpoweredIgnition = Ext.GetStat("Shout_Ignition_Empowered")
    EmpoweredIgnition.Description = "<font size='19'>Нанесите [1] противникам и подожгите/расплавьте поверхности и облака в [2] радиусе вокруг вас.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>Повторите базовый эффект.<br><font color='46b195'>2 (требование: 5 Пирокинетика): </font>Получите способность «Возгорание x1» на 3 хода.<br><font color='46b195'>3 (требование: 9 Пирокинетика): </font>Союзники в радиусе 15м, у которых есть как минимум 1 очко Пирокинетики, бесплатной реакцией ритуала используют «Возгорание». За каждого участника ритуала повторите базовый эффект 2 раза (не накладывает 'сожжение').<br> </font>"

    local Ignition2 = Ext.GetStat("Shout_Ignition_Splendor")
    Ignition2.Description = "<font size='19'>Нанесите [1] противникам и подожгите/расплавьте поверхности и облака в [2] радиусе вокруг вас.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>Повторите базовый эффект.<br><font color='46b195'>2 (требование: 5 Пирокинетика): </font>Получите способность «Возгорание x1» на 3 хода.<br><font color='46b195'>3 (требование: 9 Пирокинетика): </font>Союзники в радиусе 15м, у которых есть как минимум 1 очко Пирокинетики, бесплатной реакцией ритуала используют «Возгорание». За каждого участника ритуала повторите базовый эффект 2 раза (не накладывает 'сожжение').<br> </font>"

    local FireWhip = Ext.GetStat("Target_FireWhip")
    FireWhip.Description = "<font size='19'>Ударьте противника огненным хлыстом, нанося [1].<br><br><font color='ff9e9e'>Subjugated III</font> требует 7 <font color='c80030'>Battered</font>:<br>Уменьшенная вероятность нападения на владельца эффекта (при атаке получает урон водой), штраф к восстановлению ОД.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>+25% урона (+4% за Пирокинетику) в момент применения.<br><font color='46b195'>2 (требование: 5 Пирокинетика): </font>Накладывает 2 стака <font color='188EDE'>Harried</font> (+0.35 за Пирокинетику).<br><font color='46b195'>3 (требование: 9 Пирокинетика): </font>Получите способность «Огненный хлыст x1» на 3 хода, который имеет область действия 3м и 1 ход перезарядки.<br><font color='858580' size='18' face='Averia Serif'><br>Описания уровневых эффектов есть в дневнике.</font></font>"

    local EmpoweredFireWhip = Ext.GetStat("Target_FireWhip_Empowered")
    EmpoweredFireWhip.Description = "<font size='19'>Ударьте противника огненным хлыстом, нанося [1].<br><br><font color='ff9e9e'>Subjugated III</font> требует 7 <font color='c80030'>Battered</font>:<br>Уменьшенная вероятность нападения на владельца эффекта (при атаке получает урон водой), штраф к восстановлению ОД.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>+25% урона (+4% за Пирокинетику) в момент применения.<br><font color='46b195'>2 (требование: 5 Пирокинетика): </font>Накладывает 2 стака <font color='188EDE'>Harried</font> (+0.35 за Пирокинетику).<br><font color='46b195'>3 (требование: 9 Пирокинетика): </font>Получите способность «Огненный хлыст x1» на 3 хода, который имеет область действия 3м и 1 ход перезарядки.<br><font color='858580' size='18' face='Averia Serif'><br>Описания уровневых эффектов есть в дневнике.</font></font>"

    local VacuumAura = Ext.GetStat("Shout_VacuumAura")
    VacuumAura.Description = "<font size='19'>Нанесите [1] противникам в [2] радиусе вокруг вас.<br><br><font color='6a6b90'>Squelched III</font> требует 7 <font color='188EDE'>Harried</font>:<br>Немота, снижение инициативы, трата ОД при использовании способностей перемещения.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>Получите эффект 'Аура вакуума' на 2 хода. Повторное наложение эффектов способности на всех противников, зашедших в радиус и на противников в радиусе на начало вашего хода.<br><font color='46b195'>2 (требование: 5 Аэротеургия): </font>Вместо предыдущих бонусов насыщения Истоком: Получите эффект 'Аура вакуума' на 3 хода, который наносит двойной урон в момент применения и в начале ваших ходов. Накладывает 'удушение' на 2 хода на противников зашедших в радиус и на противников в радиусе на начало вашего хода.<br><font color='46b195'>3 (требование: 9 Аэротеургия): </font>Эффект длится на 1 ход дольше и наносит тройной урон в начале ваших ходов. Восстановите 1 очко Истока.<br><font color='858580' size='18' face='Averia Serif'><br>Описания уровневых эффектов есть в дневнике.</font></font>"

    local ElementalTotem = Ext.GetStat("Summon_TotemFromSurface")
    ElementalTotem.Description = "<font size='19'>Призовите тотем на 3 хода, который стреляет в противников каждый свой ход.<br>Тип тотема, урон, и эффект в зависимости от поверхности:<br><font color='ffffff'>- Обычный тотем:</font> физическая атака.<br><font color='ffffff'>- Кровавый тотем:</font> физ/кровотечение.<br><font size='18'><font color='ffffff'>- Нефтяной тотем:</font> земля/Slowed I.</font><br><font color='ffffff'>- Ядовитый тотем:</font> яд/отравление.<br><font color='ffffff'>- Водяной тотем:</font> вода/влага.<br><font color='ffffff'>- Электр. тотем:</font> воздух/электризует.<br><font color='ffffff'>- Огненный тотем:</font> огонь/поджигает.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>Призовите еще один тотем.<br><font color='46b195'>2 (требование: 5 Призывание): </font>Призывает еще по одному тотему рядом с вами и вашими контролируемыми призванными существами. Созданные тотемы получают эффект 'Языки пламени' на 3 хода.<br><font color='46b195'>3 (требование: 9 Призывание): </font>'Перегрузка' на 4 хода и 'Непоколебимость' на 2 хода на все созданные тотемы. Получите способность «Тотем стихий x1» на 4 хода, без перезарядки.<br> </font>"

    local EmpoweredElementalTotem = Ext.GetStat("Summon_TotemFromSurface_Empowered")
    EmpoweredElementalTotem.Description = "<font size='19'>Призовите тотем на 3 хода, который стреляет в противников каждый свой ход.<br><font color='ffffff'>- Обычный тотем:</font> физическая атака.<br><font color='ffffff'>- Кровавый тотем:</font> физическая атака, накладывает кровотечение.<br><font size='18'><font color='ffffff'>- Нефтяной тотем:</font> урон землей, накладывает Slowed I.</font><br><font color='ffffff'>- Ядовитый тотем:</font> ядовитая атака, накладывает отравление.<br><font color='ffffff'>- Водяной тотем:</font> водяная атака, накладывает влагу.<br><font color='ffffff'>- Электрический тотем:</font> атака воздухом, электризует поверхности.<br><font color='ffffff'>- Огненный тотем:</font> огненная атака, поджигает поверхности.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>Призовите еще один тотем.<br><font color='46b195'>2 (требование: 5 Призывание): </font>Призывает еще по одному тотему рядом с вами и вашими контролируемыми призванными существами. Созданные тотемы получают эффект 'Языки пламени' на 3 хода.<br><font color='46b195'>3 (требование: 9 Призывание): </font>Накладывает эффект 'Перегрузка' на 4 хода и 'Избегание смерти' на 2 хода на все созданные тотемы. Получите способность «Тотем стихий x1» на 4 хода, без перезарядки.<br> </font>"

    local ChainLightning = Ext.GetStat("Projectile_ChainLightning")
    ChainLightning.Description = "<font size='19'>Выпустите молнию в целевого персонажа, которая разделяется на [3] противников в [2] радиусе и наносит [1] каждой цели.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>+25% урона (+4% за Аэротеургию) в момент применения.<br><font color='46b195'>2 (требование: 5 Аэротеургия): </font>+40% урона (+8% за Аэротеургию) в момент применения. Восстановите 2 ОД.<br><font color='46b195'>3 (требование: 9 Аэротеургия): </font>Получите способность «Цепная молния x1», перезарядка 1 ход, может быть применена в течение 1 хода, при этом длительность обновляется при применении. Союзники в радиусе 13м, у которых есть хотя бы 1 Аэротеургия, бесплатной реакцией ритуала используют «Цепную молнию» на вашу цель. За каждого участника ритуала получите по +3% урона за Аэротеургию.<br> </font>"

    local ChainLightning = Ext.GetStat("Projectile_ChainLightning_Empowered")
    ChainLightning.Description = "<font size='19'>Выпустите молнию в целевого персонажа, которая разделяется на [3] противников в [2] радиусе и наносит [1] каждой цели.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>+25% урона (+4% за Аэротеургию) в момент применения.<br><font color='46b195'>2 (требование: 5 Аэротеургия): </font>+40% урона (+8% за Аэротеургию) в момент применения. Восстановите 2 ОД.<br><font color='46b195'>3 (требование: 9 Аэротеургия): </font>Получите способность «Цепная молния x1», перезарядка 1 ход, может быть применена в течение 1 хода, при этом длительность обновляется при применении. Союзники в радиусе 13м, у которых есть хотя бы 1 Аэротеургия, бесплатной реакцией ритуала используют «Цепную молнию» на вашу цель. За каждого участника ритуала получите по +3% урона за Аэротеургию.<br> </font>"

