    ChainLightning.Description = "<font size='19'>Выпустите молнию в целевого персонажа, которая разделяется на [3] противников в [2] радиусе и наносит [1] каждой цели.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>+25% урона (+4% за Аэротеургию) в момент применения.<br><font color='46b195'>2 (требование: 5 Аэротеургия): </font>+40% урона (+8% за Аэротеургию) в момент применения. Восстановите 2 ОД.<br><font color='46b195'>3 (требование: 9 Аэротеургия): </font>Получите способность «Цепная молния x1», перезарядка 1 ход, может быть применена в течение 1 хода, при этом длительность обновляется при применении. Союзники в радиусе 13м, у которых есть хотя бы 1 Аэротеургия, бесплатной реакцией ритуала используют 'Цепную молнию' на вашу цель. За каждого участника ритуала получите по +3% урона за Аэротеургию.<br> </font>"

    local LaserRay = Ext.GetStat("Zone_LaserRay")
    LaserRay.Description = "<font size='19'>Полоса нестерпимого жара с областью 1м сжигает воздух и наносит [1] всем персонажем на пути, создавая огненные облака.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>+25% урона (+4% за Пирокинетику) в момент применения.<br><font color='46b195'>2 (требование: 5 Пирокинетика): </font>+20% урона (+4% за Пирокинетику) в момент применения. Получите способность «Лазерный луч x1» на 1 ход, перезарядка 1 ход, стоимость 3 ОД, наносит на 50% больше урона и создает проклятые огненные облака.<br><font color='46b195'>3 (требование: 9 Пирокинетика): </font>+20% урона (+4% за Пирокинетику) в момент применения. Способность «Лазерный луч x1» может быть применена еще 3 хода.<br> </font>"

    local EmpoweredLaserRay = Ext.GetStat("Zone_LaserRay_Empowered")
    EmpoweredLaserRay.Description = "<font size='19'>Полоса нестерпимого жара с областью 1м сжигает воздух и наносит [1] всем персонажем на пути, создавая огненные облака.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>+25% урона (+4% за Пирокинетику) в момент применения.<br><font color='46b195'>2 (требование: 5 Пирокинетика): </font>+20% урона (+4% за Пирокинетику) в момент применения. Получите способность «Лазерный луч x1» на 1 ход, перезарядка 1 ход, стоимость 3 ОД, наносит на 50% больше урона и создает проклятые огненные облака.<br><font color='46b195'>3 (требование: 9 Пирокинетика): </font>+20% урона (+4% за Пирокинетику) в момент применения. Способность «Лазерный луч x1» может быть применена еще 3 хода.<br> </font>"

    local SlugLaserRay = Ext.GetStat("Zone_SlugRay")
    SlugLaserRay.Description = "<font size='19'>Полоса нестерпимого жара с областью 1м сжигает воздух и наносит [1] всем персонажем на пути, создавая огненные облака.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>+25% урона (+4% за Пирокинетику) в момент применения.<br><font color='46b195'>2 (требование: 5 Пирокинетика): </font>+20% урона (+4% за Пирокинетику) в момент применения. Получите способность «Лазерный луч x1» на 1 ход, перезарядка 1 ход, стоимость 3 ОД, наносит на 50% больше урона и создает проклятые огненные облака.<br><font color='46b195'>3 (требование: 9 Пирокинетика): </font>+20% урона (+4% за Пирокинетику) в момент применения. Способность «Лазерный луч x1» может быть применена еще 3 хода.<br> </font>"

    local TargetSourceVampirism = Ext.GetStat("Target_SourceVampirism")
    TargetSourceVampirism.Description = "<font size='19'>Украдите 1 очко Истока у персонажа без магической или физической брони.<br>Способность может быть применена на трупе, только если он умер с как минимум 1 очком Истока.<br>Вне боя, может быть применена на трупах и духах.</font>"

    local Overpower = Ext.GetStat("Target_Overpower")
    Overpower.Description = "<font size='19'>Нанесите [1].<br><br><font color='b823cb'>Vulnerable III</font> требует 7 <font color='c80030'>Battered</font>:<br>Порча (урон от лечения). Проще наложить стаки Battered/Harried.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>+5% точности (+1% за Военное дело) в момент применения. Нанесите урон в размере 20% от вашей физической брони (+2% за Военное дело) напрямую физ. броне цели.<br><font color='46b195'>2 (требование: 5 Военное дело): </font>Накладывает 2 <font color='c80030'>Battered</font> (+0.2 за Военное дело). +30% от вашей физической брони (+3% за Военное дело) напрямую физ. броне цели.<br><font color='46b195'>3 (требование: 9 Военное дело): </font>+40% урона (+8% за Военное дело) в момент применения. Накладывает 2 <font color='c80030'>Battered</font> (+0.2 за Военное дело). Нанесите урон в размере 25% от вашей общей брони (+5% за Военное дело) как физ. урон.<br><font color='858580' size='18' face='Averia Serif'><br>Описания уровневых эффектов есть в дневнике.</font></font>"

    local IncarnateFossilStrike = Ext.GetStat("Projectile_IncarnatePyroclasticRock")
    IncarnateFossilStrike.Description = "<font size='19'>Запустите огромный булыжник, который наносит [1] и создает поверхность нефти в [2] радиусе.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>+25% урона (+4% за Геомантию) в момент применения. <br><font color='46b195'>2 (требование: 5 Геомантия): </font>+40% урона (+8% за Геомантию) в момент применения. <br><font color='46b195'>3 (требование: 9 Геомантия): </font>Союзники в радиусе 15м, у которых есть как минимум 1 очко Геомантии, бесплатной реакцией ритуала используют «Каменный удар» на всех видимых противников в радиусе 13м от них. Повторно используется на всех противников в радиусе 13м.<br> </font>"

    local FireSlug = Ext.GetStat("Summon_FireSlug")
    FireSlug.Description = "<font size='19'>Призовите супер крутого слизня Вупсеня, который затащит вам любой бой. Обладает способностями «Огненный шар» и «Натиск слизня».</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>Вупсень получает 2 хода генерации Истока<br><font color='46b195'>2 (требование: 5 Призывание): </font>Вупсень получает 2 очка Истока и способность «Огненное клеймо».<br><font color='46b195'>3 (требование: 9 Призывание): </font>Вупсень получает способность «Лазерный луч». Восстановите 1 очко Истока.<br> </font>"

    local SummonIncarnate = Ext.GetStat("Summon_Incarnate")
    SummonIncarnate.Description = "<font size='19'>Призовите <font color='ffffff'>Инкарната</font>, который получает определенный бонус, в зависимости от поверхности, на которой он появился. Меняется его тип атаки, сопротивления и доступные способности. После того, как вы откроете генерацию Истока, Инкарнат получит способность, позволяющую ему забрать у вас 1 очко Истока.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>Инкарнат получает 3 хода генерации Истока.<br><font color='46b195'>2 (требование: 5 Призывание): </font>Инкарнат получает все ваши значения умений, 2 очка Истока и следующие две способности: Ослепляющее излучение/Замкнутая цепь, Загрязнение/Ядовитая волна, Сверхновая/Самовозгорание, Бросок пыли/Дрожь земли, Черная пелена/Взрыв трупа или Взрыв стужи/Ритуал исцеления.<br><font color='46b195'>3 (требование: 9 Призывание): </font>Инкарнат больше не тратит лимит призванных существ и получает способность «Вытягивание Истока». Восстановите 1 очко Истока.<br> </font>"

    local Commune = Ext.GetStat("Target_SoulMate")
    Commune.Description = "<font size='19'>Наложите эффект <font color='ffffff'>Вторая половина</font> на союзника, который передает ему все ваши эффекты восстановления брони и здоровья.<br><font color='c80030'>Заплатите до 3 ОД:</font> За каждое недостающее ОД вы получаете 2 стака <font color='c80030'>Battered</font> и <font color='188EDE'>Harried</font>.<br><font color='6CCBFF'>Очищает хрупкость, заряд, Ataxia, Vulnerable и Terrified.</font></font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>У вас всегда остается как минимум 1 ОД после применения. +1 ход длительности.<br><font color='46b195'>2 (требование: 5 Призывание): </font>Стаки <font color='c80030'>Battered</font> и <font color='188EDE'>Harried</font> за недостающие ОД больше не накладываются. Получите способность «Вторая половина x1» до конца вашего хода.<br><font color='46b195'>3 (требование: 9 Призывание): </font>Способность «Вторая половина x1» может быть применена в течение 3 ходов. Восстановите 1 очко Истока.<br> </font>"

    local EmpoweredCommune = Ext.GetStat("Target_SoulMate_Empowered")
    EmpoweredCommune.Description = "<font size='19'>Наложите эффект <font color='ffffff'>Вторая половина</font> на союзника, который передает ему все ваши эффекты восстановления брони и здоровья.<br><font color='c80030'>Заплатите до 3 ОД:</font> За каждое недостающее ОД вы получаете 2 стака <font color='c80030'>Battered</font> и <font color='188EDE'>Harried</font>.<br><font color='6CCBFF'>Очищает хрупкость, заряд, Ataxia, Vulnerable и Terrified.</font></font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>У вас всегда остается как минимум 1 ОД после применения. +1 ход длительности.<br><font color='46b195'>2 (требование: 5 Призывание): </font>Стаки <font color='c80030'>Battered</font> и <font color='188EDE'>Harried</font> за недостающие ОД больше не накладываются. Получите способность «Вторая половина x1» до конца вашего хода.<br><font color='46b195'>3 (требование: 9 Призывание): </font>Способность «Вторая половина x1» может быть применена в течение 3 ходов. Восстановите 1 очко Истока.<br> </font>"

    local BoneCage = Ext.GetStat("Shout_BoneCage")
    BoneCage.Description = "<font size='19'>Получите [1] + [1] за каждый труп в [2] радиусе вокруг вас.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font><font color='6CCBFF'>Снимите +0.25 Battered и Harried</font> за Некромантию, за каждый труп в радиусе 13м.<br><font color='46b195'>2 (требование: 5 Некромантия): </font>Получите +0.25% сопротивления физ. урону и +1% максимальной физической брони за Некромантию, за каждый труп в радиусе 13м.<br><font color='46b195'>3 (требование: 9 Некромантия): </font>Союзники в радиусе 15м, у которых есть как минимум 1 очко Некромантии, бесплатной реакцией ритуала создают трупы в случайном месте в радиусе 13м вокруг вас. За каждого участника ритуала получите +0.4% сопротивления физ. урону за Некромантию, за каждый труп в радиусе 13м.<br> </font>"

    local BonefideSlayer = Ext.GetStat("Summon_Bonefide Slayer")
    BonefideSlayer.Description = "<font size='19'>Сильный, классный и красивый скелет, вооруженный косой. Обладает высокими значениями восприятия и ловкости, способностями «Смерч», «Таран» и «Порча»</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>Скелет-убийца получает способность «Калечащий удар» и 3 хода генерации Истока.<br><font color='46b195'>2 (требование: 5 Некромантия): </font>Скелет-убийца получает способности «Кровавый дождь», «Кровавый голод» и 2 очка Истока.<br><font color='46b195'>3 (требование: 9 Некромантия): </font>Скелет-убийца получает способности «Возгорание», «Всеобщее охлаждение» и «Загрязнение». Больше не тратит лимит призванных существ. Восстановите 1 очко Истока.<br> </font>"

    local HungryFlower = Ext.GetStat("Summon_ArtilleryPlant")
    HungryFlower.Description = "<font size='19'>Призовите плотоядный цветок, который может отравлять ваших врагов. Обладает способностями «Ядовитая волна», «Все сразу» и «Кислотные споры».</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>Голодный цветок получает 2 хода генерации Истока<br><font color='46b195'>2 (требование: 5 Призывание): </font>Голодный цветок получает 2 очка Истока и способность «Отравленная сталь».<br><font color='46b195'>3 (требование: 9 Призывание): </font>Голодный цветок получает способность «Дрожь земли». Восстановите 1 очко Истока.<br> </font>"

    local LaunchBomber = Ext.GetStat("Projectile_LaunchBomber")
    LaunchBomber.Description = "<font size='19'>Метните механизм, который способен взрываться, нанося урон огнем и создавая огненную повехность радиусом 4м.<br><br><font color='858580' size='18' face='Averia Serif'>Не тратит ваш лимит призванных существ.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>После взрыва создает неконтролируемую маленькую версию себя (Малая Заводная игрушка), которая не получает урона от поверхностей и использует взрыв на свой ход. Войдите в скрытность после применения.<br><font color='46b195'>2 (требование: 5 Призывание): </font>+1 Малая Заводная игрушка. Восстановите 1 очко Истока.<br><font color='46b195'>3 (требование: 9 Призывание): </font>+4 Малых Заводных игрушек. Восстановите 3 ОД.<br> </font>"

    local SuicideBomber = Ext.GetStat("Shout_SuicideBomberExplosion")
    SuicideBomber.Description = "<font size='19'>Взрыв наносит [1] всем в радиусе [2].</font>"

    local DimensionalBolt = Ext.GetStat("Projectile_DimensionalBolt")
    DimensionalBolt.Description = "<font size='19'>Наносит [1] ед. урона огнем, водой, воздухом или землей, накладывает соответствующий стихии статус и создает поверхность.<br><br><font color='797980'>Dazzled III</font> требует 7 <font color='188EDE'>Harried</font>:<br>Слепота (видимость 3м), нельзя обнаружить персонажей в скрытности, снижение точности и уклонения.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>Взрывается 3 раза, нанося [2] урона огнем, водой, воздухом или землей, накладывает статусы и создает поверхности, соответствующие стихиям.<br><font color='46b195'>2 (требование: 5 Призывание): </font>Выстреливает в каждого противника в радиусе 8м по 4 раза, наносит [3], [4], [5] и [6] в 2м области, накладывает статусы и создает поверхности, соответствующие стихиям.<br><font color='46b195'>3 (требование: 9 Призывание): </font>Сдетонируйте 'хрупкость' на всех противниках в радиусе 8м. Получите способности «Бросок пыли x1», «Огненный хлыст x1», «Взрыв стужи x1» и «Цепная молния x1» на 1 ход. Восстановите 2 ОД.<br><font color='858580' size='18' face='Averia Serif'><br>Описания уровневых эффектов есть в дневнике.</font></font>"

    local WormTremor = Ext.GetStat("Target_WormTremor")
    WormTremor.Description = "<font size='19'>Нанесите [1] персонажам в [2] области.<br><br><font color='6a6b90'>Squelched III</font> требует 7 <font color='188EDE'>Harried</font>:<br>Немота, снижение инициативы, трата ОД при использовании способностей перемещения.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>Накладывает 'кислоту' и 'кровотечение' на 3 хода.<br><font color='46b195'>2 (требование: 5 Геомантия): </font>Накладывает 2 стака <font color='c80030'>Battered</font> и <font color='188EDE'>Harried</font>. Накладывает эффекты <font color='B97A57'>Slowed</font> и <font color='639594'>Weakened</font> (вплоть до III уровней) на 2 хода. Накладывает 'кровоизлияние' на 2 хода.<br><font color='46b195'>3 (требование: 9 Геомантия): </font>От центра области применяется способность «Землетрясение». Накладывает 2 стака <font color='c80030'>Battered</font> и <font color='188EDE'>Harried</font>, и также Withered и 'разъедание' на 1 ход.<br><font color='858580' size='18' face='Averia Serif'><br>Описания уровневых эффектов есть в дневнике.</font></font>"

    local PlantWormTremor = Ext.GetStat("Target_PlantWormTremor")
    PlantWormTremor.Description = "<font size='19'>Нанесите [1] персонажам в [2] области.<br><br><font color='6a6b90'>Squelched III</font> требует 7 <font color='188EDE'>Harried</font>:<br>Немота, снижение инициативы, трата ОД при использовании способностей перемещения.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>Накладывает 'кислоту' и 'кровотечение' на 3 хода.<br><font color='46b195'>2 (требование: 5 Геомантия): </font>Накладывает 2 стака <font color='c80030'>Battered</font> и <font color='188EDE'>Harried</font>. Накладывает эффекты <font color='B97A57'>Slowed</font> и <font color='639594'>Weakened</font> (вплоть до III уровней) на 2 хода. Накладывает 'кровоизлияние' на 2 хода.<br><font color='46b195'>3 (требование: 9 Геомантия): </font>От центра области применяется способность «Землетрясение». Накладывает 2 стака <font color='c80030'>Battered</font> и <font color='188EDE'>Harried</font>, и также Withered и 'разъедание' на 1 ход.<br><font color='858580' size='18' face='Averia Serif'><br>Описания уровневых эффектов есть в дневнике.</font></font>"

    local DeepFreeze = Ext.GetStat("Cone_Shatter")
    DeepFreeze.Description = "<font size='19'>Нанесите [1] противникам в [3]-градусном [2] конусе. Накладывает эффект <font color='7F25D4'>Terrified</font> (вплоть до III уровня), если у противника есть эффект <font color='ffffff'>Обморожение</font>.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>Получите эффект 'Обжигающий холод' до конца своего хода: когда вы накладываете 'хрупкость', нанесите [4] (до модификаторов). Этот эффект не срабатывает на попадание «Глубокой заморозкой» и ограничено одним срабатыванием на одно действие.<br><font color='46b195'>2 (требование: 5 Гидрософистика): </font>Обжигающий холод длится 1 ход и может срабатывать на попадание с «Глубокой заморозки». Восстановите 2 ОД и 1 очко Истока.<br><font color='46b195'>3 (требование: 9 Гидрософистика): </font>Вместо предыдущих бонусов насыщения Истоком: Получите 'Обжигающий холод' на 3 хода, срабатывает на попадание с «Глубокой заморозки». Повторите базовый эффект. Восстановите 2 ОД.<br><font color='858580' size='18' face='Averia Serif'><br>Описания уровневых эффектов есть в дневнике.</font></font>"

    local WaterRain = Ext.GetStat("Rain_Water")
    WaterRain.Description = "<font size='19'>Дождь обрушивается на целевую область, нанося [3] противникам при применении и в начале следующего хода, создавая поверхность воды в [1] радиусе.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>Перед применением, очистите все поверхности и облака в области действия.<br><font color='46b195'>2 (требование: 5 Гидрософистика): </font>Получите способность «Дождь x1», может быть использована до конца хода, имеет +5м дальность применения, наносит [2] и накладывает 'хрупкость'.<br><font color='46b195'>3 (требование: 9 Гидрософистика): </font>Способность «Дождь x1» может быть применена в течение 3 ходов, накладывает 'удушение' на 2 хода и наносит двойной урон.<br> </font>"

    local WaterRain2 = Ext.GetStat("Rain_Water_Empowered")
    WaterRain2.Description = "<font size='19'>Дождь обрушивается на целевую область, нанося [2] противникам при применении и в начале следующего хода, создавая поверхность воды в [1] радиусе.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>Перед применением, очистите все поверхности и облака в области действия.<br><font color='46b195'>2 (требование: 5 Гидрософистика): </font>Получите способность «Дождь x1», может быть использована до конца хода, имеет +5м дальность применения, наносит [3] и накладывает 'хрупкость'.<br><font color='46b195'>3 (требование: 9 Гидрософистика): </font>Способность «Дождь x1» может быть применена в течение 3 ходов, накладывает 'удушение' на 2 хода и наносит двойной урон.<br> </font>"

    local WaterRain3 = Ext.GetStat("Rain_Water_Empowered_3")
    WaterRain3.Description = "<font size='19'>Дождь обрушивается на целевую область, нанося [2] противникам при применении и в начале следующего хода, создавая поверхность воды в [1] радиусе.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>Перед применением, очистите все поверхности и облака в области действия.<br><font color='46b195'>2 (требование: 5 Гидрософистика): </font>Получите способность «Дождь x1», может быть использована до конца хода, имеет +5м дальность применения, наносит [3] и накладывает 'хрупкость'.<br><font color='46b195'>3 (требование: 9 Гидрософистика): </font>Способность «Дождь x1» может быть применена в течение 3 ходов, накладывает 'удушение' на 2 хода и наносит двойной урон.<br> </font>"

    local Contamination = Ext.GetStat("Shout_Contamination")
    Contamination.Description = "<font size='19'>Распространите ядовитую волну, которая наносит [1] противникам и союзникам нежити, превращая кровь и воду в яд в [2] радиусе вокруг вас.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>Повторите базовый эффект 1 раз.<br><font color='46b195'>2 (требование: 5 Геомантия): </font>Повторите базовый эффект 2 раза. Накладывает эффект <font color='b823cb'>Vulnerable</font> (вплоть до III  уровня) на 2 хода.<br><font color='46b195'>3 (требование: 9 Геомантия): </font>Повторите базовый эффект 2 раза. Союзники в радиусе 15м, у которых есть как минимум 1 очко в Геомантии, бесплатной реакцией ритуала используют способность «Загрязнение». Повторите базовый эффект за каждого участника ритуала.<br><font color='858580' size='18' face='Averia Serif'><br>Описания уровневых эффектов есть в дневнике.</font></font>"

    local Glaciate = Ext.GetStat("Shout_GlobalCooling")
    Glaciate.Description = "<font size='19'>Распространите леденящий холод, нанося [1] противникам и замораживая поверхности в [2] радиусе вокруг вас. Накладывает эффект <font color='ffffff'>Обморожение</font>: персонажи истекают поверхностью льда вместо крови.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>Повторите применение способности в начале следующего хода.<br><font color='46b195'>2 (требование: 5 Гидрософистика): </font>Повторное применение еще на 1 ход. Усиливает снижение сопротивлений от уровневых эффектов на 15% (+2% за Гидрософистику) на 2 хода.<br><font color='46b195'>3 (требование: 9 Гидрософистика): </font>Повторное применение еще на 1 ход. Повторное применение наносит двойной урон. +3% усиления снижения сопротивлений от уровневых эффектов за Гидрософистику.<br> </font>"

    local ArrowStorm = Ext.GetStat("ProjectileStrike_RainOfArrows")
    ArrowStorm.Description = "<font size='19'>Выпустите [2] стрел в [3] радиусе, каждая из которых наносит [1] урона всем в радиусе [4] вокруг упавшей стрелы.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>+20% урона (+4% за Мастерство охоты) в момент применения. +5% точности(+1% за Мастерство охоты) в момент применения.<br><font color='46b195'>2 (требование: 5 Мастерство охоты): </font><font color='c80030'>Заплатите на 1 ОД больше:</font> +6 стрел.<br><font color='46b195'>3 (требование: 9 Мастерство охоты): </font><font color='c80030'>Заплатите на 2 ОД больше:</font> +12 стрел. +20% урона (+4% за Мастерство охоты) в момент применения.<br> </font>"

    local TargetBless = Ext.GetStat("Target_Bless")
    TargetBless.Description = "<font size='19'>Наложите эффект <font color='ffffff'>Благословение</font> на целевого персонажа, которое дает +[2]% точности, +[3]% уклонения и +[1]% стихийных сопротивлений. Также делает благословенными поверхности и облака.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>Дает способность 'Проклятие' и +2 к восстановлению ОД.<br><font color='46b195'>2: </font>Также применяется на ближайшего союзника (не призванного) в радиусе 13м. Восстановите 1 очко Истока.<br> </font>"

    local BattleStomp = Ext.GetStat("Cone_GroundSmash")
    BattleStomp.Description = "<font size='19'>Сотрясите землю, нанося [1] противникам в [3]-градусном [2] конусе и очищая не проклятые поверхности и облака.<br><br><font color='b823cb'>Vulnerable III</font> требует 7 <font color='c80030'>Battered</font>:<br>Порча (урон от лечения). Проще наложить стаки Battered/Harried.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>+5% точности (+1% за Военное дело) и 25% урона (+4% за Военное дело) в момент применения.<br><font color='46b195'>2 (требование: 5 Военное дело): </font>+40% урона (+8% за Военное дело) в момент применения. Восстановите 2 ОД.<br><font color='46b195'>3 (требование: 9 Военное дело): </font>Применяется на всех видимых противников в радиусе 10м.<br><font color='858580' size='18' face='Averia Serif'><br>Описания уровневых эффектов есть в дневнике.</font></font>"

    local CrusherBattleStomp = Ext.GetStat("Cone_EnemyGroundSmash_BoneshapedCrusher")
    CrusherBattleStomp.Description = "<font size='19'>Сотрясите землю, нанося [1] противникам в [3]-градусном [2] конусе и очищая не проклятые поверхности и облака.<br><br><font color='b823cb'>Vulnerable III</font> требует 7 <font color='c80030'>Battered</font>:<br>Порча (урон от лечения). Проще наложить стаки Battered/Harried.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>+5% точности (+1% за Военное дело) и 25% урона (+4% за Военное дело) в момент применения.<br><font color='46b195'>2 (требование: 5 Военное дело): </font>+40% урона (+8% за Военное дело) в момент применения. Восстановите 2 ОД.<br><font color='46b195'>3 (требование: 9 Военное дело): </font>Применяется на всех видимых противников в радиусе 10м.<br><font color='858580' size='18' face='Averia Serif'><br>Описания уровневых эффектов есть в дневнике.</font></font>"

    local Earthquake = Ext.GetStat("Quake_Earthquake")
    Earthquake.Description = "<font size='19'>Расколите землю, нанося [1] персонажам в [2] радиусе вокруг вас и создавая [3] случайных поверхностей нефти в области действия.<br><br><font color='7F25D4'>Terrified III</font> требует 7 <font color='188EDE'>Harried</font>:<br>Отключение атак по возможности, нельзя обнаружить персонажей в скрытности и трата ОД от устрашения.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>Накладывает 1 <font color='188EDE'>Harried</font> (+0.15 за Геомантию).<br><font color='46b195'>2 (требование: 5 Геомантия): </font>Повторите базовый эффект. Накладывает 1 <font color='188EDE'>Harried</font> (+0.15 за Геомантию).<br><font color='46b195'>3 (требование: 9 Геомантия): </font>Повторите базовый эффект 2 раза.<br><font color='858580' size='18' face='Averia Serif'><br>Описания уровневых эффектов есть в дневнике.</font></font>"

    local PressureSpike = Ext.GetStat("Target_PressureSpike")
    PressureSpike.Description = "<font size='19'>Превратите облака в [2] области в поверхность соответствующего типа, нанося [1] противникам и очищая огненные поверхности.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>+15% урона (+3% за Аэротеургию) в момент применения. Перед применением, замените поверхности и облака в области применения на 3м наэлектризованных облаков.<br><font color='46b195'>2 (требование: 5 Аэротеургия): </font>Накладывает эффект <font color='6a6b90'>Squelched</font> (вплоть до III уровня) на 2 хода. Накладывает 2 стака <font color='188EDE'>Harried</font>. Восстановите 1 ОД.<br><font color='46b195'>3 (требование: 9 Аэротеургия): </font>+40% урона (+8% за Аэротеургию) в момент применения. Повторите базовый эффект 5 раз, с заменой урона на магический. Восстановите 1 очко Истока.<br><font color='858580' size='18' face='Averia Serif'><br>Описания уровневых эффектов есть в дневнике.</font></font>"

    local Challenge = Ext.GetStat("Target_Challenge")
    Challenge.Description = "<font size='19'>Спровоцируйте и вызовите противника на дуэль на 3 хода:<br><font color='ffffff'>-</font> Вы оба получаете бонус к урону до +50% в зависимости от здоровья оппонента (уменьшается при понижении здоровья).<br><font color='ffffff'>-</font> Если кто-то из вас умрет до окончания действия эффекта, выживший побеждает, восстанавливает [1] и получает бонус +[2]% урона, [3] и [4] на 2 хода.<br><font color='ffffff'>-</font> Если вы (игрок) далеко отойдете, совершите прыжок без сближения, или в свой ход примените действие, которое не нацелено на вас или не затрагивает вашего оппонента, то вы проигрываете и получаете [5]. <br><font color='c80030'>Таран способности проигрывают дуэль!</font></font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>Получите эффект 'Ускорение' на 2 хода.<br><font color='46b195'>2 (требование: 5 Военное дело): </font>Примените «Сокрушающий удар» на вашу цель. Получите 'Отражающий барьер' на 3 хода. Восстановите 1 очко Истока.<br><font color='46b195'>3 (требование: 9 Военное дело): </font><font color='c80030'>Заплатите на 2 ОД больше:</font> Этот эффект действует и на вас и на противника: в начале каждого вашего хода с активной дуэлью, наложите на оппонента эффект ‘Дезинтеграция: Физический’ 20% (+2% за Военное дело) до конца своего хода: при окончании эффекта цель получает процентный урон от общего полученного урона за время действия эффекта (физический урон). <br></font>"

    local MeteorShower = Ext.GetStat("ProjectileStrike_MeteorShower")
    MeteorShower.Description = "<font size='19'>Призовите [2] метеоритов в [3] область, каждый из которых наносит [1] и [5] всем в радиусе [4] вокруг каждого метеорита.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>+25% урона (+4% за Пирокинетику) в момент применения.<br><font color='46b195'>2 (требование: 5 Пирокинетика): </font>+3 метеорита. Получите способность «Метеоритный дождь x1» на 1 ход, стоимостью 4 ОД и перезарядкой 1 ход.<br><font color='46b195'>3 (требование: 9 Пирокинетика): </font>+6 метеоритов. Способность «Метеоритный дождь x1» может быть применена в течение 3 ходов.<br> </font>"

    local EmpoweredMeteorShower = Ext.GetStat("ProjectileStrike_MeteorShower_Empowered")
    EmpoweredMeteorShower.Description = "<font size='19'>Призовите [2] метеоритов в [3] область, каждый из которых наносит [1] и [5] всем в радиусе [4] вокруг каждого метеорита.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>+25% урона (+4% за Пирокинетику) в момент применения.<br><font color='46b195'>2 (требование: 5 Пирокинетика): </font>+3 meteors. Получите способность «Метеоритный дождь x1» на 1 ход, стоимостью 4 ОД и перезарядкой 1 ход.<br><font color='46b195'>3 (требование: 9 Пирокинетика): </font>+6 метеоритов. Способность «Метеоритный дождь x1» может быть применена в течение 3 ходов.<br> </font>"

    local TerrorGrenade = Ext.GetStat("Projectile_Grenade_Terror")
    TerrorGrenade.Description = "Наносит [2] и накладывает эффект <font color='7f25d4'>Terrified</font> (вплоть до II уровня) на противников в [1] области."

    local TurnToOil = Ext.GetStat("Target_Condense")
    TurnToOil.Description = "<font size='19'>Замените все поверхности и облака в области 2м поверхностью нефти. Накладывает 'окаменение' и эффект <font color='B97A57'>Slowed</font> (вплоть до II уровня) на противников.<br><font color='6CCBFF'>Очищает влагу и заряд с союзников.</font></font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>Накладывает эффект 'Застывание' на 2 хода на противников в радиусе, который наносит урон землей за каждые пройденные противником 0.5м, также создается нефть, когда противник истекает кровью. <br><font color='46b195'>2 (требование: 5 Геомантия): </font>+1 ход длительности эффекта 'Застывание'. Накладывает 2 <font color='c80030'>Battered</font> (+0.2 за Геомантию) и эффект <font color='c82300'>Ataxia</font> (вплоть до III уровня).<br><font color='46b195'>3 (требование: 9 Геомантия): </font>+1 ход длительности эффекта 'Застывание'. Накладывает 2 <font color='c80030'>Battered</font> (+0.2 за Геомантию), 'Застывание' распространяется на противников в радиусе 5м.<br><font color='858580' size='18' face='Averia Serif'><br>Описания уровневых эффектов есть в дневнике.</font></font>"

    local Squall = Ext.GetStat("Target_Squall")
    Squall.Description = "<font size='19'>Призовите бурю в целевую [2] область, которая наносит противникам [1].<br><font color='46b195'>Эта способность требует на 2 стака B/H меньше для наложение эффекта III уровня.</font><br><br><font color='797980'>Dazzled III</font> требует 7 <font color='188EDE'>Harried</font>:<br>Слепота (видимость 3м), нельзя обнаружить персонажей в скрытности, снижение точности и уклонения.<br><font color='858580' size='18' face='Averia Serif'><br>Описания уровневых эффектов есть в дневнике.</font></font>"

    local UncannyEvasion = Ext.GetStat("Target_EvasiveManeuver")
    UncannyEvasion.Description = "<font size='19'>Наложите эффект <font color='ffffff'>Необъяснимое уклонение</font> на целевого персонажа, который дает +[1]% уклонения и +0.5 движения.<br><br><font color='c80030'>Повышает утомляемость от уклонения на дополнительные 10%.</font></font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>+1 ход длительности.<br><font color='46b195'>2 (требование: 5 Аэротеургия): </font>Накладывается и на себя и на цель. Больше не повышает 'утомляемость' от уклонения. Восстановите 1 очко Истока.<br><font color='46b195'>3 (требование: 9 Аэротеургия): </font>Накладывается на всех союзников в радиусе 13м.<br> </font>"

    local LuminousRitual = Ext.GetStat("Projectile_ChainHeal")
    LuminousRitual.Description = "<font size='19'>Вы выпускаете волну целительной энергии, которая распространяется на [3] союзников (не получающих урон от лечения) или противников (получающих урон от лечения) в [2] радиусе, вылечивая [1] и восстанавливая [4] каждой цели.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>Восстановите 10% (+2% за Гидрософистику) недостающего здоровья.<br><font color='46b195'>2 (требование: 5 Гидрософистика): </font>+1м области действия вокруг каждой цели.<br><font color='46b195'>3 (требование: 9 Гидрософистика): </font>+1м области действия вокруг каждой цели. Восстановите 1 очко Истока. Союзники в радиусе 13м от цели, у которых есть как минимум 1 очко Гидрософистики, бесплатной реакцией ритуала используют «Ритуал исцеления» на вашей цели.<br> </font>"

    local IncarnateLuminousRitual = Ext.GetStat("Projectile_IncarnateChainHeal")
    IncarnateLuminousRitual.Description = "<font size='19'>Вы выпускаете волну целительной энергии, которая распространяется на  [3] союзников (не получающих урон от лечения) или противников (получающих урон от лечения) в [2] радиусе, восстанавливая [1] и восстанавливая [4] каждой цели.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>Восстановите 10% (+2% за Гидрософистику) недостающего здоровья.<br><font color='46b195'>2 (требование: 5 Гидрософистика): </font>+1м области действия вокруг каждой цели.<br><font color='46b195'>3 (требование: 9 Гидрософистика): </font>+1м области действия вокруг каждой цели. Восстановите 1 очко Истока. Союзники в радиусе 13м от цели, у которых есть как минимум 1 очко Гидрософистики, бесплатной реакцией ритуала используют «Ритуал исцеления» на вашей цели.<br> </font>"

    local LightningBolt = Ext.GetStat("Projectile_LightningBolt")
