    VampiricHunger.Description = "<font size='19'>Наложите эффект <font color='ffffff'>Жажда вампира</font> на целевого персонажа, который дает +[1]% вампиризма на 3 хода.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>Цель получает бонус +20% урона (+3% за Гидрософистику).<br><font color='46b195'>2 (требование: 5 Гидрософистика): </font>Эффект становится аурой радиусом 13м. +1 ход длительности.<br><font color='46b195'>3 (требование: 9 Гидрософистика): </font>Значение вампиризма от способности удвоено. Восстановите 1 очко Истока.<br> </font>"

    local DeathWish = Ext.GetStat("Target_DeathWish")
