    local Curare = Ext.GetStat("Target_SleepingArms")
    Curare.Description = "<font size='19'>Ударьте персонажа в незащищенное место, нанося [1].<br><br><font color='639594'>Weakened III</font> требует 7 <font color='c80030'>Battered</font>:<br>Значительное снижение урона.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>+5% точности (+1% за Искусство убийства). Накладывает эффект <font color='B97A57'>Slowed</font> (вплоть до III уровня) на 2 хода.<br><font color='46b195'>2 (требование: 5 Искусство убийства): </font>Войдите в скрытность до применения. +1 к длительности эффектов <font color='B97A57'>Slowed</font> и <font color='639594'>Weakened</font>.<br><font color='46b195'>3 (требование: 9 Искусство убийства): </font>Перед применением, войдите в скрытность и получите невидимость до конца своего хода. Восстановите 2 ОД и 1 очко Истока. +1 к длительности эффектов <font color='B97A57'>Slowed</font> и <font color='639594'>Weakened</font>.<br><font color='858580' size='18' face='Averia Serif'><br>Описания уровневых эффектов есть в дневнике.</font></font>"

    local CorruptedBlade = Ext.GetStat("Target_CorruptedBlade")
    CorruptedBlade.Description = "<font size='19'>Нанесите [1]. Наложите 'отравление' на 4 хода, если у цели менее 100% сопротивления яду. Если на цели есть эффект <font color='b823cb'>Vulnerable III</font>, наложите 'отравление' на 4 хода и 'разъедание' на 1 ход.<br><br><font color='b823cb'>Vulnerable III</font> требует 7 <font color='c80030'>Battered</font>:<br>Порча (урон от лечения). Проще наложить стаки Battered/Harried.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>+10% урона (+2% за Искусство убийства) в момент применения. Накладывает 'кровоизлияние' и 'кислоту' на 3 хода.<br><font color='46b195'>2 (требование: 5 Искусство убийства): </font>+40% урона (+8% за Искусство убийства) в момент применения. Накладывает 'разъедание' на 1 ход.<br><font color='46b195'>3 (требование: 9 Искусство убийства): </font>Получите эффект на 3 хода: один раз за раунд, при применении базовой атаки на противника, также примените на него «Порченный клинок».<br><font color='858580' size='18' face='Averia Serif'><br>Описания уровневых эффектов есть в дневнике.</font></font>"

    local IncarnateCorruptedBlade = Ext.GetStat("Target_IncarnateCorruptedBlade")
    IncarnateCorruptedBlade.Description = "<font size='19'>Поразите цель сверхъестественным токсином, нанося [1]. Накладывает 'отравление' на 4 хода, если у цели менее 100% сопротивления яду. Если на цели есть эффект <font color='b823cb'>Vulnerable III</font>, наложите 'отравление' на 4 хода и 'разъедание' на 1 ход.<br><br><font color='b823cb'>Vulnerable III</font> требует 7 <font color='c80030'>Battered</font>:<br>Порча (урон от лечения). Проще наложить стаки Battered/Harried.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>+10% урона (+2% за Искусство убийства) в момент применения. Накладывает 'кровоизлияние' и 'кислоту' на 3 хода.<br><font color='46b195'>2 (требование: 5 Искусство убийства): </font>+40% урона (+8% за Искусство убийства) в момент применения. Накладывает 'разъедание' на 1 ход.<br><font color='46b195'>3 (требование: 9 Искусство убийства): </font>Получите эффект на 3 хода: один раз за раунд, при применении базовой атаки на противника, также примените на него «Порченный клинок».<br><font color='858580' size='18' face='Averia Serif'><br>Описания уровневых эффектов есть в дневнике.</font></font>"

    local Ricochet = Ext.GetStat("Projectile_Ricochet")
    Ricochet.Description = "<font size='19'>Выпустите стрелу, которая разделяется на [3] противников в [2] радиусе и наносит [1] каждой цели.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>+5% точности (+1% за Мастерство охоты) и +25% (+4% за Мастерство охоты) урона в момент применения.<br><font color='46b195'>2 (требование: 5 Мастерство охоты): </font>Повторно выпускается 1 раз в случайного противника в радиусе 5м от цели.<br><font color='46b195'>3 (требование: 9 Мастерство охоты): </font>Повторно выпускается 2 раза в случайного противника в радиусе 5м от цели.<br> </font>"

    local Harmony = Ext.GetStat("Target_Harmony")
    Harmony.Description = "<font size='19'>Восстанавливает [1] и [2] за каждого союзного персонажа в [3] радиусе вокруг цели.<br><font color='6CCBFF'>Очищает Subjugated, Terrified и Slowed.</font></font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>Дополнительно восстанавливает по 5% от общего здоровья за каждого союзника в радиусе.<br><font color='46b195'>2 (требование: 5 Призывание): </font>Накладывает эффекты 'Магический панцирь', 'Каменная броня' и 'Ускорение' на 1 ход за каждого союзника в радиусе.<br><font color='46b195'>3 (требование: 9 Призывание): </font>Перед применением, призовите 2 Тотема стихий в радиусе 3м от цели. Восстановите 1 очко Истока.<br> </font>"

    local FavourableWind = Ext.GetStat("Shout_FavourableWind")
    FavourableWind.Description = "<font size='19'>Наложите на себя эффект <font color='ffffff'>Попутный ветер</font>, который является [1] аурой и дает +0.75 движения вам и союзникам.<br><font color='6CCBFF'>Очищает Slowed.</font></font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>Аура дает <font color='11D77A'>иммунитет к эффекту Slowed.</font><br><font color='46b195'>2 (требование: 5 Аэротеургия): </font><font color='c80030'>Заплатите на 1 ОД больше:</font> Аура дает +1 к восстановлению ОД, +1 к максимальным ОД.<br><font color='46b195'>3 (требование: 9 Аэротеургия): </font><font color='c80030'>Заплатите на 1 ОД больше:</font> Аура дает +1 к восстановлению ОД, +1 к максимальным ОД и +35% движения. +2 хода длительности.<br> </font>"

    local Haste = Ext.GetStat("Target_Haste")
    Haste.Description = "<font size='19'>Наложите эффект <font color='ffffff'>Ускорение</font> на целевого персонажа, который дает +1 движения, +2 к стартовым ОД, +2 к восстановлению ОД.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>+1.0 движения. +1 ход длительности.<br><font color='46b195'>2 (требование: 5 Пирокинетика): </font>Накладывается на всех союзников в радиусе 13м.<br><font color='46b195'>3 (требование: 9 Пирокинетика): </font><font color='c80030'>Заплатите на 2 ОД больше:</font> Дает +2 к восстановлению и максимальным ОД. +1 ход длительности.<br> </font>"

    local TremorGrenade = Ext.GetStat("Projectile_Grenade_Tremor")
    TremorGrenade.Description = "Наносит [1] всем целям в [2] радиусе."

    local TargetCurse = Ext.GetStat("Target_Curse")
    TargetCurse.Description = "<font size='19'>Наложите эффект <font color='ffffff'>Проклятие</font> на целевого персонажа, который снижает точность на [2]%, уклонение на [3]% и сопротивления на [1]%. Также делает проклятыми поверхности и облака.</font>"

    local MercySkill = Ext.GetStat("Shout_AMER_Benevolence_Mercy")
    MercySkill.Description = "<font size='19'>Активируйте Benevolence на союзниках в радиусе 13м.</font> "

    local Equalize = Ext.GetStat("Target_Equalize")
    Equalize.Description = "<font size='19'>Снимите с противников в радиусе 8м все стаки <font color='c80030'>Battered</font> или <font color='188EDE'>Harried</font> (наибольшее) и перенесите это значение в противоположный тип (наименьшее).</font> "

    local SpinWeb = Ext.GetStat("Projectile_SpinWeb")
