    local BoneshapedCrusher = Ext.GetStat("Summon_AMER_BoneshapedCrusher")
    BoneshapedCrusher.Description = "<font size='19'>Призовите костяного голема, у которого есть способности «Сокрушающий удар», «Таран», «Черная пелена», «Костяная клетка», «Некрофеоз» и «Взрыв трупа».<br>Начинает бой с 1 очком Истока и генерацией Истока на 2 хода.<br><br><font color='858580' size='18' face='Averia Serif'>Не тратит лимит призванных существ.</font></font> "

    local CryogenicStasis = Ext.GetStat("Target_CryogenicStasis")
    CryogenicStasis.Description = "<font size='19'>Наложите эффект <font color='ffffff'>Криогенный стазис</font> на целевого союзника, который покрывает персонажа льдом, защищающим его от любого урона. Восстанавливает [1] после окончания действия.<br><font color='11D77A'>Дает иммунитет ко всему (ну почти).</font></font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>Цель накладывает провокацию на противников в радиусе 5м.<br><font color='46b195'>2 (требование: 5 Гидрософистика): </font>Цель отражает 50% урона в атакующих. Восстановите 1 очко Истока.<br><font color='46b195'>3 (требование: 9 Гидрософистика): </font>Цель получает +8 к восстановлению и максимальным ОД на 2 хода.<br> </font>"

    local PeaceOfMind = Ext.GetStat("Target_BurnMyEyes")
    PeaceOfMind.Description = "<font size='19'>Наложите <font color='ffffff'>Чистоту разума</font> на целевого персонажа, которая дает +[1] ловкости, мощи, +[2] восприятия и +20% точности.<br><font color='6CCBFF'>Очищает Dazzled, Subjugated, Terrified, Weakened, Ярость(не Берсерка) и безумие.</font></font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>+1 ход длительности. Также накладывается на ближайшего союзника (не призванного) в радиусе 13м.<br><font color='46b195'>2 (требование: 5 Пирокинетика): </font>Накладывается на всех союзников в радиусе 13м. Дает +10% Восприятия(+4% за Пирокинетику).<br><font color='46b195'>3 (требование: 9 Пирокинетика): </font> Дает <font color='11D77A'>иммунитет к эффектам Subjugated и Terrified.</font> Восстановите 1 очко Истока.<br> </font>"

    local CleanseWounds = Ext.GetStat("Target_CleanseWounds")
    CleanseWounds.Description = "<font size='19'>Восстановите [1] целевому персонажу.<br><font color='6CCBFF'>Очищает кровотечение, сожжение, отравление и Ataxia.</font></font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>Восстанавливает 35% недостающего здоровья (+4% за Гидрософистику).<br><font color='46b195'>2 (требование: 5 Гидрософистика): </font>Накладывается на всех союзников (не получающих урон от лечения) и на всех противников (получающих урон от лечения) в радиусе 15м.<br><font color='46b195'>3 (требование: 9 Гидрософистика): </font>Получите способность «Очищение ран x1» на 4 хода, без перезарядки. Восстановите 1 очко Истока.<br> </font>"

    local CleanseWounds2 = Ext.GetStat("Target_CleanseWounds_Empowered")
