    local BatteringRam = Ext.GetStat("Rush_BatteringRam")
    BatteringRam.Description = "<font size='19'>Пронеситесь вперед, нанося [1] всем противникам на своем пути.<br><br><font color='639594'>Weakened III</font> требует 7 <font color='c80030'>Battered</font>:<br>Значительное снижение урона.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>+5% точности (+1% за Военное дело) и +15% урона (+3% за Военное дело) в момент применения. Восстановите 2 ОД.<br><font color='46b195'>2 (требование: 5 Военное дело): </font>Получите способность «Таран x1», которая стоит 0 ОД и может быть применена до конца вашего хода. Восстановите 2 ОД и 1 очко Истока.<br><font color='46b195'>3 (требование: 9 Военное дело): </font>Способность «Таран x1» может быть применена в течение 3 ходов.<br><font color='858580' size='18' face='Averia Serif'><br>Описания уровневых эффектов есть в дневнике.</font></font>"

