    CrusherBatteringRam.Description = "<font size='19'>Пронеситесь вперед, нанося [1] всем противникам на своем пути.<br><br><font color='639594'>Weakened III</font> требует 7 <font color='c80030'>Battered</font>:<br>Значительное снижение урона.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>+5% точности (+1% за Военное дело) и +15% урона (+3% за Военное дело) в момент применения. Восстановите 2 ОД.<br><font color='46b195'>2 (требование: 5 Военное дело): </font>Получите способность «Таран x1», которая стоит 0 ОД и может быть применена до конца вашего хода. Восстановите 2 ОД и 1 очко Истока.<br><font color='46b195'>3 (требование: 9 Военное дело): </font>Способность «Таран x1» может быть применена в течение 3 ходов.<br><font color='858580' size='18' face='Averia Serif'><br>Описания уровневых эффектов есть в дневнике.</font></font>"

    local RupturedTendons = Ext.GetStat("Target_KneeBreaker")
    RupturedTendons.Description = "<font size='19'>Повредите сухожилия цели, нанося [1] и накладывая эффект 'Разрыв сухожилий', который наносит [2] за каждые пройденные целью 0.75м.<br><font size='12' color='595959'>Побежали!</font></font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>+5% точности (+1% за Искусство убийства) и +25% урона (+4% за Искусство убийства) в момент применения.<br><font color='46b195'>2 (требование: 5 Искусство убийства): </font>+1 ход длительности. Войдите в скрытность, если способность была использована из скрытности.<br><font color='46b195'>3 (требование: 9 Искусство убийства): </font>+1 ход длительности. Урон от эффекта увеличен на 35%. Если применено из скрытности, накладывается на всех противников в радиусе 5м от цели.<br> </font>"

    local DaggersDrawn = Ext.GetStat("Target_DaggersDrawn")
    DaggersDrawn.Description = "<font size='19'>Нанесите 5 ударов, каждый из которых наносит [1].</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>+5% точности (+1% за Искусство убийства). +25% урона (+4% за Искусство убийства) в момент применения.<br><font color='46b195'>2 (требование: 5 Искусство убийства): </font>+40% урона (+8% за Искусство убийства) в момент применения. Войдите в скрытность до применения.<br><font color='46b195'>3 (требование: 9 Искусство убийства): </font>Союзники в радиусе 13м от цели, у которых есть как минимум 1 очко Гидрософистики или Искусства убийства, бесплатной реакцией ритуала используют «Ледяной веер» или «Метательный нож» (Веер в приоритете) на вашу цель. Получите +3% урона за Искусство убийства за каждого участника ритуала. Если используется из скрытности, ваши попадания накладывают +2 <font color='c80030'>Battered</font> или <font color='188EDE'>Harried</font> в момент применения.<br> </font>"

    local Execute = Ext.GetStat("Target_Fatality")
    Execute.Description = "<font size='19'>Нанесите [1]. Если применяется из скрытности или невидимости, нанесите двойной урон и наложите эффект <font color='c82300'>Ataxia</font> (вплоть до III уровня). Цель (не Босс) умирает, если у нее осталось меньше здоровья, чем значение полученного от этой способности урона.<br><br><font color='c82300'>Ataxia III</font> требует 7 <font color='c80030'>Battered</font>:<br>Истощение (обезоружение), замедление и снижение уклонения.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>+5% точности (+1% за Искусство убийства). +25% урона (+4% за Искусство убийства) в момент применения.<br><font color='46b195'>2 (требование: 5 Искусство убийства): </font>+40% урона (+8% за Искусство убийства) в момент применения.<br><font color='46b195'>3 (требование: 9 Искусство убийства): </font>Повторите базовый эффект. Войдите в скрытность после применения. Если цель умирает, восстановите 1 очко Истока.<br><font color='858580' size='18' face='Averia Serif'><br>Описания уровневых эффектов есть в дневнике.</font></font>"

    local InnerDemonTerrify = Ext.GetStat("Target_Terrify")
    InnerDemonTerrify.Description = "<font size='19'>Уничтожьте [1].<br><br><font color='7F25D4'>Terrified III</font> требует 7 <font color='188EDE'>Harried</font>:<br>Отключение атак по возможности, нельзя обнаружить персонажей в скрытности и трата ОД от устрашения.</font><font color='858580' size='18' face='Averia Serif'><br><br>Описания уровневых эффектов есть в дневнике.</font>"

    local InnerDemon = Ext.GetStat("Shout_InnerDemon")
    InnerDemon.Description = "<font size='19'>Наложите на себя эффект <font color='ffffff'>Внутренний демон</font>, который <font color='11D77A'>защищает вас от устрашения</font> (эффект траты ОД от Terrified), дает [1], +[2] мощи и способности «Запугивание» и «Демоническое наставничество». «Демоническое наставничество» наносит урон всем противникам, что зашли или передвинулись в радиусе 3м вокруг вас. «Запугивание» уничтожает магическую броню и накладывает эффект <font color='7F25D4'>Terrified</font> (вплоть до III уровня).</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>Накладывает 'Демоническое наставничество' на 3 хода на всех ваших неконтролируемых призванных существ.<br><font color='46b195'>2 (требование: 5 Призывание): </font>Накладывает 'Внутреннего демона' на всех ваших контролируемых призванных существ.<br><font color='46b195'>3 (требование: 9 Призывание): </font>Накладывает 'Внутреннего демона' на всех союзников в бою.<br> </font>"

    local ShacklesOfPain = Ext.GetStat("Target_ShacklesOfPain")
    ShacklesOfPain.Description = "<font size='19'>Наложите эффект <font color='ffffff'>Оковы боли</font> на целевого персонажа. Весь получаемый вами урон также перенаправляется на связанного с вами персонажа. Если связанный персонаж заканчивает свой ход дальше 13м от источника оков, то оковы спадают и заменяются эффектом <font color='ff9e9e'>Subjugated</font> (вплоть до III уровня).<br><br><font color='c80030'>Оковы боли снижают ваш множитель от мощи на 75%.</font></font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>Компенсирует сниженный бонус от мощи на 5% за Некромантию, до минимума штрафа в -25%.<br><font color='46b195'>2 (требование: 5 Некромантия): </font>Применяется на одного видимого противника в радиусе 13м от цели.<br><font color='46b195'>3 (требование: 9 Некромантия): </font>Применяется на всех видимых противников в радиусе 13м от цели.<br> </font>"

    local SuperConductor = Ext.GetStat("Projectile_Superconductor")
    SuperConductor.Description = "<font size='19'>Выпустите молнии во всех противников вокруг вас, которые распространяется на другую цель в радиусе [2], нанося [1] каждой цели.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>+25% урона (+4% за Аэротеургию) в момент применения.<br><font color='46b195'>2 (требование: 5 Аэротеургия): </font>+20% урона(+4% за Аэротеургию) в момент применения. Повторите базовый эффект.<br><font color='46b195'>3 (требование: 9 Аэротеургия): </font>+20% урона(+4% за Аэротеургию) в момент применения. Получите эффект 'Сверхпроводник' на 3 хода: один раз за раунд, когда на вас накладывается 'заряд', снимите его и повторите базовый эффект способности на всех противников в радиусе 13м. Дополнительно, на конец своих ходов, повторите базовый эффект на всех противников с эффектом 'заряда' в радиусе 13м.<br> </font>"

    local Sabotage = Ext.GetStat("Target_Sabotage")
    Sabotage.Description = "<font size='19'>Наложите <font color='ffffff'>Саботаж</font>;<br>- Стоимость всех действий (кроме движения) повышена на 1 ОД.<br>- Взорвите случайную гранату или стрелу у цели. Если у цели >100% сопротивления яду, то ядовитое исключается.<br>- После окончания действия эффекта, цель получает иммунитет к саботажу (штраф на ОД и подрыв, но <font color='797980'>Dazzled</font> все еще будет накладываться).</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>Взрывается доп. граната или стрела. Войдите в скрытность после применения.<br><font color='46b195'>2 (требование: 5 Искусство убийства): </font>+40% урона (+8% за Искусство убийства) в момент применения. Применяется на всех видимых противников в радиусе 13м. Восстановите 1 очко Истока.<br><font color='46b195'>3 (требование: 9 Искусство убийства): </font>+1 ход длительности. +1 ОД к стоимости действий от 'Саботажа'.<br><font color='858580' size='18' face='Averia Serif'><br>Описания уровневых эффектов есть в дневнике.</font></font>"

    local MendMetal = Ext.GetStat("Shout_MendMetal")
    MendMetal.Description = "<font size='19'>Наложите эффект <font color='ffffff'>Исцеление металла</font> на себя и союзников в [2] от вас. Этот эффект моментально восстанавливает [1] и потом такое же количество в начале вашего хода.<br><font color='6CCBFF'>Очищает окаменение, заряд, кислоту и кровотечение.</font></font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>Восстанавливает 25% физической брони (+2.5% за Геомантию) в момент применения.<br><font color='46b195'>2 (требование: 5 Геомантия): </font>Восстанавливает 15% от недостающей физической брони (+3% за Геомантию) и <font color='6CCBFF'>снимает 1 стак Battered</font> каждый ход. Радиус увеличивается до 10м.<br><font color='46b195'>3 (требование: 9 Геомантия): </font>+1 ход длительности. Восстанавливает 25% физической брони (+2.5% за Геомантию) в момент применения. Восстановите 2 ОД и 1 очко Истока.<br> </font>"

    local SoothingCold = Ext.GetStat("Shout_FrostAura")
    SoothingCold.Description = "<font size='19'>Наложите эффект <font color='ffffff'>Успокаивающий холод</font> на себя и союзников в [2] от вас. Этот эффект моментально восстанавливает [1], и потом такое же количество в начале вашего хода.<br><font color='6CCBFF'>Очищает отравление, сожжение, удушение и хрупкость.</font></font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>Восстанавливает 25% (+2.5% за Гидрософистику) от общей магической брони в момент применения.<br><font color='46b195'>2 (требование: 5 Гидрософистика): </font>Восстанавливает 30% от недостающей магической брони (+2% за Гидрософистику). Радиус увеличивается до 10м. <font color='6CCBFF'>Снимает 1 стак Harried</font> каждый ход.<br><font color='46b195'>3 (требование: 9 Гидрософистика): </font>+1 ход длительности. <font color='6CCBFF'>Снимает 1 стак Harried</font> (+0.2 за Гидрософистику) каждый ход. Восстановите 2 ОД и 1 очко Истока.<br> </font>"

    local Firebrand = Ext.GetStat("Shout_FireBrand")
    Firebrand.Description = "<font size='19'>Наложите на себя эффект <font color='ffffff'>Огненное клеймо</font>, который дает [2] ауру, которая добавляет [1] (до модификаторов) к оружейным атакам для вас и ваших союзников.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>Бонусный урон увеличен на 85%. <br><font color='46b195'>2 (требование: 5 Пирокинетика): </font>Бонусный урон увеличен на 85%. +1 ход длительности.<br><font color='46b195'>3 (требование: 9 Пирокинетика): </font>Радиус ауры увеличен до 13м. Восстановите 1 очко Истока.<br> </font>"

    local SlugFirebrand = Ext.GetStat("Shout_SlugFireBrand")
    SlugFirebrand.Description = "<font size='19'>Наложите на себя эффект <font color='ffffff'>Огненное клеймо</font>, который дает [2] ауру, которая добавляет [1] (до модификаторов) к оружейным атакам для вас и ваших союзников.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>Бонусный урон увеличен на 85%. <br><font color='46b195'>2 (требование: 5 Пирокинетика): </font>Бонусный урон увеличен на 85%. +1 ход длительности.<br><font color='46b195'>3 (требование: 9 Пирокинетика): </font>Радиус ауры увеличен до 13м. Восстановите 1 очко Истока.<br> </font>"

    local SiphonPoison = Ext.GetStat("Shout_SiphonPoison")
    SiphonPoison.Description = "<font size='19'>Покройте свое оружие ядом, добавляя ему [3] (до модификаторов) , также ваши оружейные атаки теперь накладывают 'отравление' на 3 хода. Дополнительно, поглотите ядовитые поверхности и облака в [2] радиусе от вас, добавляя до [1] своему оружию, в зависимости от размера поглощенной поверхности.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>+1 ход длительности.<br><font color='46b195'>2 (требование: 5 Геомантия): </font>Перед применением, создайте 8м ядовитой поверхности и облаков вокруг себя.<br><font color='46b195'>3 (требование: 9 Геомантия): </font>+2 хода длительности. Восстановите 2 ОД и 1 очко Истока.<br></font>  "

    local ErraticWisp = Ext.GetStat("Target_Windwalker")
    ErraticWisp.Description = "<font size='19'>Наложите эффект <font color='ffffff'>Изменчивый бриз</font> на целевого персонажа, который дает +[1]% сопротивления воздуху, <font color='11D77A'>иммунитет к поверхностям</font> и также цель будет телепортироваться в случайном направлении в радиусе 10м при получении урона от оружия.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>Эффект дает +1.0 движения.<br><font color='46b195'>2 (требование: 5 Аэротеургия): </font>+1 ход длительности. Накладывается и на цель и на вас.<br><font color='46b195'>3 (требование: 9 Аэротеургия): </font>Когда получаете стаки <font color='c80030'>Battered</font> или <font color='188EDE'>Harried</font>, уменьшите их количество на 1. Накладывается на всех союзников в радиусе 13м.<br> </font>"

    local OilyCarapace = Ext.GetStat("Target_AMER_OilyCarapace")
    OilyCarapace.Description = "<font size='19'>Наложите эффект <font color='B97A57'>Slowed</font> (вплоть до III уровня) противникам в [2] области и создайте под ними 2м поверхности нефти. Затем союзники в области действия могут поглотить нефтяные поверхности в радиусе 2м вокруг себя, восстанавливая до [1], в зависимости от размера поглощенной поверхности и также <font color='6CCBFF'>снимая с себя 2 стака Battered.<br>Очищает эффекты Slowed и Рой</font>.<br><br><font color='B97A57'>Slowed III</font> требует 7 <font color='188EDE'>Harried</font>:<br>Значительное замедление, штраф к восстановлению ОД, повышение стоимости заклинаний.</font><br><br><font color='46b195'>Насыщения Истоком:</font><font size='17'><br><font color='46b195'>1: </font>Союзники получают +5% сопротивления физ. урону (+1% за Геомантию), и <font color='11D77A'>иммунитет к окаменению и Slowed</font> на 2 хода.<br><font color='46b195'>2 (требование: 5 Геомантия): </font>Накладывается снова на всех противников в радиусе 13м.<br><font color='46b195'>3 (требование: 9 Геомантия): </font>Союзники получают +2% сопротивления физ. урону за Геомантию. Восстановите 1 очко Истока.<br><font color='858580' size='18' face='Averia Serif'><br>Описания уровневых эффектов есть в дневнике.</font></font>"

end
Ext.RegisterListener("StatsLoaded", PatchSkillText)